{
  "name": "CivicSense: Citizen Reporting Platform",
  "description": "A comprehensive portal for citizens to report local issues like garbage dumping and water leakage, and for authorities to track, manage, and resolve them with visual proof.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export enum ReportStatus {
  PENDING = 'PENDING',
  IN_PROGRESS = 'IN_PROGRESS',
  RESOLVED = 'RESOLVED',
  REJECTED = 'REJECTED'
}

export enum ReportCategory {
  GARBAGE = 'Garbage Dumping',
  WATER_LEAKAGE = 'Water Leakage',
  TREE_CUTTING = 'Illegal Tree Cutting',
  SMUGGLING = 'Smuggling Activity',
  POTHOLES = 'Potholes/Road Damage',
  OTHER = 'Other'
}

export interface User {
  id: string;
  username: string;
  email: string;
  mobile: string;
  role: 'citizen' | 'authority';
}

export interface Report {
  id: string;
  citizenId: string;
  citizenName: string;
  title: string;
  description: string;
  category: ReportCategory;
  location: string;
  timestamp: number;
  status: ReportStatus;
  mediaUrl: string; // Base64 for simulation
  mediaType: 'image' | 'video';
  aiAnalysis?: string;
  workDoneMediaUrl?: string;
  workDoneDescription?: string;
  resolvedAt?: number;
  notified: boolean;
}

export interface AuthoritySession {
  userId: string;
  lastActive: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeReportMedia = async (base64Data: string, mimeType: string, description: string) => {
  try {
    const ai = getAI();
    const model = 'gemini-3-flash-preview';

    const imagePart = {
      inlineData: {
        mimeType,
        data: base64Data.split(',')[1] || base64Data,
      },
    };

    const prompt = `
      Analyze this image of a citizen report regarding "${description}". 
      1. Briefly describe what is seen.
      2. Categorize the severity (Low, Medium, High).
      3. Suggest 3 immediate action steps for local authorities.
      Format the response as a clean summary.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: { parts: [imagePart, { text: prompt }] },
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis failed:", error);
    return "AI analysis unavailable at this time.";
  }
};

export const getResolutionSummary = async (originalDesc: string, resolutionDesc: string) => {
  try {
    const ai = getAI();
    const model = 'gemini-3-flash-preview';

    const prompt = `
      Issue Reported: ${originalDesc}
      Resolution provided by Authority: ${resolutionDesc}

      Generate a concise, professional notification message for the citizen informing them that the work is complete.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    return "The reported issue has been resolved. Thank you for your patience.";
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Root element not found");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory, 
  AuthoritySession 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';

// Mock Storage Helper
const STORAGE_KEY = 'civic_sense_data';
const loadData = () => {
  const saved = localStorage.getItem(STORAGE_KEY);
  return saved ? JSON.parse(saved) : { reports: [], users: [], authSessions: [] };
};
const saveData = (data: any) => localStorage.setItem(STORAGE_KEY, JSON.stringify(data));

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isUploading, setIsUploading] = useState(false);
  const [notifications, setNotifications] = useState<string[]>([]);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status === ReportStatus.PENDING).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  useEffect(() => {
    const data = loadData();
    setReports(data.reports);
  }, []);

  const handleLogin = (formData: any) => {
    const data = loadData();
    if (role === 'authority') {
      if (data.authSessions.length >= 5 && !data.authSessions.includes(formData.username)) {
        alert("Maximum 5 authority members are already logged in.");
        return;
      }
      if (!data.authSessions.includes(formData.username)) {
        data.authSessions.push(formData.username);
      }
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username: formData.username,
      email: formData.email || '',
      mobile: formData.mobile || '',
      role: role
    };

    setUser(newUser);
    setView('dashboard');
    saveData({ ...data, reports });
  };

  const handleLogout = () => {
    if (user?.role === 'authority') {
      const data = loadData();
      data.authSessions = data.authSessions.filter((id: string) => id !== user.username);
      saveData({ ...data, reports });
    }
    setUser(null);
    setView('login');
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReport: Report = {
        id: Math.random().toString(36).substr(2, 9),
        citizenId: user.id,
        citizenName: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        mediaUrl: base64,
        mediaType: file.type.startsWith('video') ? 'video' : 'image',
        aiAnalysis,
        notified: false
      };

      const updatedReports = [newReport, ...reports];
      setReports(updatedReports);
      saveData({ ...loadData(), reports: updatedReports });
      setIsUploading(false);
      (e.target as HTMLFormElement).reset();
    };
    reader.readAsDataURL(file);
  };

  const resolveReport = async (reportId: string, resolutionDesc: string, mediaFile: File | null) => {
    const reportIndex = reports.findIndex(r => r.id === reportId);
    if (reportIndex === -1) return;

    let workDoneMediaUrl = '';
    if (mediaFile) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const report = reports[reportIndex];
    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const updatedReports = [...reports];
    updatedReports[reportIndex] = {
      ...report,
      status: ReportStatus.RESOLVED,
      workDoneDescription: resolutionDesc,
      workDoneMediaUrl,
      resolvedAt: Date.now(),
      aiAnalysis: aiSummary // Update with resolution summary for citizen
    };

    setReports(updatedReports);
    saveData({ ...loadData(), reports: updatedReports });
    alert(`Citizen ${report.citizenName} has been notified via email/mobile.`);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-gradient-to-br from-blue-50 to-indigo-100">
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-100">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-full text-white mb-4">
              <i className="fas fa-city text-2xl"></i>
            </div>
            <h1 className="text-3xl font-bold text-slate-900">CivicSense</h1>
            <p className="text-slate-500">Citizen Reporting & Governance Portal</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-lg mb-6">
            <button 
              onClick={() => setRole('citizen')}
              className={`flex-1 py-2 rounded-md text-sm font-medium transition ${role === 'citizen' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen
            </button>
            <button 
              onClick={() => setRole('authority')}
              className={`flex-1 py-2 rounded-md text-sm font-medium transition ${role === 'authority' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority
            </button>
          </div>

          <form onSubmit={(e) => { e.preventDefault(); handleLogin(Object.fromEntries(new FormData(e.currentTarget))); }} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Username</label>
              <input name="username" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Enter username" />
            </div>
            {role === 'citizen' && (
              <>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                  <input name="email" type="email" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="email@example.com" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mobile Number</label>
                  <input name="mobile" type="tel" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="+1234567890" />
                </div>
              </>
            )}
            <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200">
              Access Portal
            </button>
          </form>
          {role === 'authority' && (
            <p className="mt-4 text-xs text-center text-slate-400">
              * Max 5 authority members allowed simultaneously.
            </p>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <i className="fas fa-city text-indigo-600 text-xl"></i>
              <span className="font-bold text-xl tracking-tight">CivicSense</span>
              <span className="bg-slate-100 text-slate-600 text-[10px] uppercase font-bold px-2 py-0.5 rounded-full border border-slate-200">
                {user?.role}
              </span>
            </div>
            <div className="flex items-center gap-4">
              <div className="hidden sm:block text-right">
                <p className="text-sm font-semibold text-slate-900">{user?.username}</p>
                <p className="text-xs text-slate-500">{user?.email}</p>
              </div>
              <button onClick={handleLogout} className="text-slate-400 hover:text-red-600 transition-colors">
                <i className="fas fa-sign-out-alt text-lg"></i>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {user?.role === 'citizen' ? (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Report Form */}
            <div className="lg:col-span-1">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                  <i className="fas fa-plus-circle text-indigo-600"></i>
                  File a Report
                </h2>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Issue Category</label>
                    <select name="category" className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                    <textarea name="description" required rows={3} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500" placeholder="Details of the activity..."></textarea>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Location / Address</label>
                    <input name="location" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500" placeholder="Enter landmark or address" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Upload Proof (Image/Video)</label>
                    <div className="border-2 border-dashed border-slate-200 rounded-lg p-4 text-center hover:border-indigo-400 transition-colors cursor-pointer relative">
                      <input type="file" name="media" accept="image/*,video/*" required className="absolute inset-0 opacity-0 cursor-pointer" />
                      <i className="fas fa-cloud-upload-alt text-slate-400 text-2xl mb-2"></i>
                      <p className="text-xs text-slate-500">Click or drag proof here</p>
                    </div>
                  </div>
                  <button 
                    disabled={isUploading}
                    className={`w-full py-3 rounded-lg font-bold text-white shadow-lg transition-all ${isUploading ? 'bg-slate-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}
                  >
                    {isUploading ? (
                      <span className="flex items-center justify-center gap-2">
                        <i className="fas fa-circle-notch animate-spin"></i> Processing with AI...
                      </span>
                    ) : 'Submit Incident Report'}
                  </button>
                </form>
              </div>
            </div>

            {/* Right: History */}
            <div className="lg:col-span-2 space-y-6">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <i className="fas fa-history text-indigo-600"></i>
                Your Reported Incidents
              </h2>
              {reports.filter(r => r.citizenId === user.id).length === 0 ? (
                <div className="bg-white p-12 rounded-2xl text-center border border-slate-200">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <i className="fas fa-clipboard-list text-3xl text-slate-300"></i>
                  </div>
                  <p className="text-slate-500 font-medium">No reports submitted yet.</p>
                </div>
              ) : (
                reports.filter(r => r.citizenId === user.id).map(report => (
                  <div key={report.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
                    <div className="p-6">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                            report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                          }`}>
                            {report.status}
                          </span>
                          <h3 className="text-lg font-bold text-slate-900 mt-2">{report.title}</h3>
                          <p className="text-xs text-slate-400 flex items-center gap-1 mt-1">
                            <i className="fas fa-map-marker-alt"></i> {report.location} • {new Date(report.timestamp).toLocaleDateString()}
                          </p>
                        </div>
                        {report.status === ReportStatus.RESOLVED && (
                          <div className="bg-indigo-50 p-2 rounded-lg border border-indigo-100 animate-pulse">
                            <i className="fas fa-bell text-indigo-600"></i>
                          </div>
                        )}
                      </div>
                      <p className="text-slate-600 mb-4">{report.description}</p>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="relative rounded-xl overflow-hidden bg-slate-100 border border-slate-200 aspect-video">
                          {report.mediaType === 'image' ? (
                            <img src={report.mediaUrl} className="w-full h-full object-cover" alt="Proof" />
                          ) : (
                            <video src={report.mediaUrl} className="w-full h-full object-cover" controls />
                          )}
                        </div>
                        <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                          <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">AI Assessment</h4>
                          <p className="text-sm text-slate-700 italic">"{report.aiAnalysis}"</p>
                        </div>
                      </div>

                      {report.status === ReportStatus.RESOLVED && (
                        <div className="mt-6 pt-6 border-t border-slate-100">
                          <h4 className="text-sm font-bold text-green-700 mb-3 flex items-center gap-2">
                            <i className="fas fa-check-circle"></i> Resolution Proof
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                             {report.workDoneMediaUrl && (
                                <img src={report.workDoneMediaUrl} className="rounded-xl aspect-video object-cover border border-slate-200" alt="Work Done" />
                             )}
                             <div>
                                <p className="text-sm text-slate-700 font-medium">{report.workDoneDescription}</p>
                                <p className="text-xs text-slate-400 mt-2">Resolved on: {new Date(report.resolvedAt!).toLocaleString()}</p>
                             </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-8">
            {/* Analytics Dashboard */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <p className="text-slate-400 text-sm font-medium">Total Reports</p>
                <p className="text-3xl font-bold text-slate-900">{stats.total}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <p className="text-yellow-600 text-sm font-medium">Pending</p>
                <p className="text-3xl font-bold text-slate-900">{stats.pending}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <p className="text-green-600 text-sm font-medium">Resolved</p>
                <p className="text-3xl font-bold text-slate-900">{stats.resolved}</p>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <p className="text-indigo-600 text-sm font-medium">Success Rate</p>
                <p className="text-3xl font-bold text-slate-900">
                  {stats.total > 0 ? Math.round((stats.resolved / stats.total) * 100) : 0}%
                </p>
              </div>
            </div>

            {/* Authority Report View */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <h2 className="text-xl font-bold">Inbound Citizen Reports</h2>
                <div className="flex gap-2">
                  <span className="bg-white px-3 py-1 rounded-full text-xs font-semibold border border-slate-200 text-slate-600">
                    <i className="fas fa-users-cog mr-1"></i> 5/5 Capacity
                  </span>
                </div>
              </div>
              <div className="divide-y divide-slate-100">
                {reports.length === 0 ? (
                  <div className="p-20 text-center">
                    <p className="text-slate-400">No reports requiring attention.</p>
                  </div>
                ) : (
                  reports.map(report => (
                    <div key={report.id} className="p-6 hover:bg-slate-50/50 transition-colors">
                      <div className="flex flex-col lg:flex-row gap-8">
                        {/* Report Details */}
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-2">
                            <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                              report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                            }`}>
                              {report.status}
                            </span>
                            <span className="text-xs font-bold text-indigo-600 uppercase tracking-tighter">{report.category}</span>
                          </div>
                          <h3 className="text-lg font-bold text-slate-900 mb-1">{report.description}</h3>
                          <div className="flex items-center gap-4 text-xs text-slate-400 mb-4">
                            <span><i className="fas fa-user mr-1"></i> {report.citizenName}</span>
                            <span><i className="fas fa-map-marker-alt mr-1"></i> {report.location}</span>
                            <span><i className="fas fa-clock mr-1"></i> {new Date(report.timestamp).toLocaleString()}</span>
                          </div>

                          <div className="grid grid-cols-2 gap-4">
                            <div className="aspect-video rounded-xl bg-slate-200 overflow-hidden border border-slate-200">
                              {report.mediaType === 'image' ? (
                                <img src={report.mediaUrl} className="w-full h-full object-cover" alt="Issue" />
                              ) : (
                                <video src={report.mediaUrl} className="w-full h-full object-cover" />
                              )}
                            </div>
                            <div className="p-4 bg-indigo-50/50 rounded-xl border border-indigo-100">
                              <p className="text-[10px] font-bold text-indigo-400 uppercase mb-1">Internal AI Analysis</p>
                              <p className="text-sm text-indigo-900 font-medium italic">{report.aiAnalysis}</p>
                            </div>
                          </div>
                        </div>

                        {/* Action Tab */}
                        <div className="lg:w-80 bg-slate-50 p-6 rounded-2xl border border-slate-200">
                          {report.status === ReportStatus.RESOLVED ? (
                            <div className="h-full flex flex-col items-center justify-center text-center">
                              <i className="fas fa-check-double text-green-500 text-4xl mb-3"></i>
                              <h4 className="font-bold text-slate-900">Task Completed</h4>
                              <p className="text-sm text-slate-500">Citizen notified on resolution.</p>
                            </div>
                          ) : (
                            <form 
                              className="space-y-4"
                              onSubmit={(e) => {
                                e.preventDefault();
                                const fd = new FormData(e.currentTarget);
                                resolveReport(report.id, fd.get('res_desc') as string, fd.get('res_media') as File);
                              }}
                            >
                              <h4 className="font-bold text-slate-900">Resolve Issue</h4>
                              <div>
                                <label className="text-xs font-semibold text-slate-500 block mb-1">Work Description</label>
                                <textarea name="res_desc" required className="w-full text-sm p-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Explain the action taken..."></textarea>
                              </div>
                              <div>
                                <label className="text-xs font-semibold text-slate-500 block mb-1">Upload Work Proof (Required)</label>
                                <input name="res_media" type="file" accept="image/*" required className="text-xs w-full" />
                              </div>
                              <button className="w-full bg-green-600 text-white py-2 rounded-lg font-bold hover:bg-green-700 transition shadow-lg shadow-green-100">
                                Mark as Done & Notify
                              </button>
                            </form>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
