import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory, 
  AuthoritySession 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';

// Mock Storage Helper
const STORAGE_KEY = 'civic_sense_data';
const loadData = () => {
  const saved = localStorage.getItem(STORAGE_KEY);
  return saved ? JSON.parse(saved) : { reports: [], users: [], authSessions: [] };
};
const saveData = (data: any) => localStorage.setItem(STORAGE_KEY, JSON.stringify(data));

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isUploading, setIsUploading] = useState(false);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status === ReportStatus.PENDING).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  useEffect(() => {
    const data = loadData();
    setReports(data.reports);
  }, []);

  const handleLogin = (formData: any) => {
    const data = loadData();
    const username = formData.username;

    if (role === 'authority') {
      // Restriction: Only "Atharv" can be authority
      if (username !== 'Atharv') {
        alert("Unauthorized. Only user 'Atharv' is registered as the authority.");
        return;
      }

      // Maintain the 5 member/session limit for the authority role
      if (data.authSessions.length >= 5 && !data.authSessions.includes(username)) {
        alert("Maximum 5 authority sessions are already active.");
        return;
      }

      if (!data.authSessions.includes(username)) {
        data.authSessions.push(username);
      }
    }

    const newUser: User = {
      id: role === 'authority' ? 'auth_atharv' : Math.random().toString(36).substr(2, 9),
      username: username,
      email: formData.email || (role === 'authority' ? 'atharv.authority@gov.in' : ''),
      mobile: formData.mobile || '',
      role: role
    };

    setUser(newUser);
    setView('dashboard');
    saveData({ ...data, reports });
  };

  const handleLogout = () => {
    if (user?.role === 'authority') {
      const data = loadData();
      data.authSessions = data.authSessions.filter((id: string) => id !== user.username);
      saveData({ ...data, reports });
    }
    setUser(null);
    setView('login');
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReport: Report = {
        id: Math.random().toString(36).substr(2, 9),
        citizenId: user.id,
        citizenName: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        mediaUrl: base64,
        mediaType: file.type.startsWith('video') ? 'video' : 'image',
        aiAnalysis,
        notified: false
      };

      const updatedReports = [newReport, ...reports];
      setReports(updatedReports);
      saveData({ ...loadData(), reports: updatedReports });
      setIsUploading(false);
      (e.target as HTMLFormElement).reset();
    };
    reader.readAsDataURL(file);
  };

  const resolveReport = async (reportId: string, resolutionDesc: string, mediaFile: File | null) => {
    const reportIndex = reports.findIndex(r => r.id === reportId);
    if (reportIndex === -1) return;

    let workDoneMediaUrl = '';
    if (mediaFile) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const report = reports[reportIndex];
    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const updatedReports = [...reports];
    updatedReports[reportIndex] = {
      ...report,
      status: ReportStatus.RESOLVED,
      workDoneDescription: resolutionDesc,
      workDoneMediaUrl,
      resolvedAt: Date.now(),
      aiAnalysis: aiSummary
    };

    setReports(updatedReports);
    saveData({ ...loadData(), reports: updatedReports });
    alert(`Notification: Work complete. Citizen ${report.citizenName} has been informed.`);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-gradient-to-br from-blue-50 to-indigo-100">
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-100">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-full text-white mb-4">
              <i className="fas fa-city text-2xl"></i>
            </div>
            <h1 className="text-3xl font-bold text-slate-900">CivicSense</h1>
            <p className="text-slate-500">Governance & Reporting Portal</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-lg mb-6">
            <button 
              onClick={() => setRole('citizen')}
              className={`flex-1 py-2 rounded-md text-sm font-medium transition ${role === 'citizen' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen
            </button>
            <button 
              onClick={() => setRole('authority')}
              className={`flex-1 py-2 rounded-md text-sm font-medium transition ${role === 'authority' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority
            </button>
          </div>

          <form onSubmit={(e) => { e.preventDefault(); handleLogin(Object.fromEntries(new FormData(e.currentTarget))); }} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                {role === 'authority' ? 'Authority Username' : 'Username'}
              </label>
              <input name="username" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder={role === 'authority' ? 'Enter Atharv' : 'Enter username'} />
            </div>
            {role === 'citizen' && (
              <>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                  <input name="email" type="email" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="email@example.com" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Mobile Number</label>
                  <input name="mobile" type="tel" required className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="+1234567890" />
                </div>
              </>
            )}
            <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200">
              {role === 'authority' ? 'Secure Authority Login' : 'Access Portal'}
            </button>
          </form>
          {role === 'authority' && (
            <p className="mt-4 text-xs text-center text-slate-500 italic">
              * Note: Only username <strong>Atharv</strong> is permitted for authority access.
            </p>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <i className="fas fa-city text-indigo-600 text-xl"></i>
              <span className="font-bold text-xl tracking-tight">CivicSense</span>
              <span className="bg-slate-100 text-slate-600 text-[10px] uppercase font-bold px-2 py-0.5 rounded-full border border-slate-200">
                {user?.role}
              </span>
            </div>
            <div className="flex items-center gap-4">
              <div className="hidden sm:block text-right">
                <p className="text-sm font-semibold text-slate-900">{user?.username}</p>
                <p className="text-xs text-slate-500">{user?.email}</p>
              </div>
              <button onClick={handleLogout} className="text-slate-400 hover:text-red-600 transition-colors">
                <i className="fas fa-sign-out-alt text-lg"></i>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {user?.role === 'citizen' ? (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
