              {reports.filter(r => r.citizenId === user.id).length === 0 ? (
                <div className="bg-white p-16 rounded-3xl text-center border border-slate-200 shadow-sm">
                  <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <i className="fas fa-file-invoice text-4xl text-slate-200"></i>
                  </div>
                  <h3 className="text-lg font-bold text-slate-900 mb-2">No Reports Yet</h3>
                  <p className="text-slate-500 text-sm max-w-xs mx-auto">Your active reports and their resolution progress will appear here.</p>
