                      <div className="flex flex-col sm:flex-row justify-between items-start gap-4 mb-6">
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-2">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-extrabold uppercase tracking-widest ${
                              report.status === ReportStatus.RESOLVED ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {report.status}
                            </span>
                            <span className="text-xs font-bold text-indigo-600 uppercase">{report.category}</span>
                          </div>
                          <h3 className="text-xl font-bold text-slate-900 leading-tight">{report.description}</h3>
                          <p className="text-xs text-slate-400 flex items-center gap-2 mt-2">
