                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="group relative rounded-2xl overflow-hidden bg-slate-100 border border-slate-200 aspect-video shadow-inner">
                          {report.mediaType === 'image' ? (
                            <img src={report.mediaUrl} className="w-full h-full object-cover transition-transform group-hover:scale-105" alt="Proof" />
