                            <span className="flex items-center gap-2"><i className="fas fa-map-pin text-red-400"></i> {report.location}</span>
                            <span className="flex items-center gap-2"><i className="fas fa-history text-slate-400"></i> {new Date(report.timestamp).toLocaleString()}</span>
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="group relative aspect-video rounded-3xl bg-slate-100 overflow-hidden border border-slate-200 shadow-lg">
                              {report.mediaType === 'image' ? (
                                <img src={report.mediaUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="Issue Evidence" />
