import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status === ReportStatus.PENDING).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .order('timestamp', { ascending: false });

      if (!error && data) {
        setReports(data);
      }
      setIsLoading(false);
    };

    fetchReports();

    // Subscribe to changes
    const channels = supabase.channel('custom-all-channel')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleLogin = async (formData: any) => {
    const username = formData.username;
    const password = formData.password;

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check global authority sessions in Supabase
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Login system error. Please try again.");
        return;
      }

      if (sessions.length >= 5 && !sessions.find(s => s.username === username)) {
        alert("Maximum 5 authority sessions are already active globally.");
        return;
      }

      // Record session
      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });
    }

    const newUser: User = {
      id: role === 'authority' ? 'auth_atharv' : Math.random().toString(36).substr(2, 9),
      username: username,
      email: formData.email || (role === 'authority' ? 'authority@civicsense.gov' : ''),
      mobile: formData.mobile || '',
      role: role
    };

    // Upsert user for persistence
    await supabase.from('users').upsert({
      id: newUser.id,
      username: newUser.username,
      email: newUser.email,
      mobile: newUser.mobile,
      role: newUser.role
    });

    setUser(newUser);
    setView('dashboard');
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report. Error: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const resolveReport = async (reportId: string, resolutionDesc: string, mediaFile: File | null) => {
    const report = reports.find(r => r.id === reportId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary // Update with resolution summary for citizen
      })
      .eq('id', reportId);

    if (error) {
      alert("Failed to update report: " + error.message);
    } else {
      alert(`Success: Notification triggered for ${report.citizen_name}. Case closed.`);
    }
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg shadow-indigo-200 transform rotate-3">
              <i className="fas fa-landmark text-2xl"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
            <p className="text-slate-500 text-sm mt-1">Smart Governance & Cloud Storage</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-xl mb-8">
            <button 
              onClick={() => setRole('citizen')}
              className={`flex-1 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 ${role === 'citizen' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen Portal
            </button>
            <button 
              onClick={() => setRole('authority')}
              className={`flex-1 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 ${role === 'authority' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority Login
            </button>
          </div>

          <form onSubmit={(e) => { e.preventDefault(); handleLogin(Object.fromEntries(new FormData(e.currentTarget))); }} className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">
                {role === 'authority' ? 'Officer ID' : 'Full Name / Username'}
              </label>
              <div className="relative">
                <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                  <i className="fas fa-user-circle"></i>
                </span>
                <input name="username" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" placeholder={role === 'authority' ? 'Enter ID' : 'e.g. John Doe'} />
              </div>
            </div>

            {role === 'authority' ? (
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Secure Password</label>
                <div className="relative">
                  <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                    <i className="fas fa-shield-alt"></i>
                  </span>
                  <input name="password" type="password" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="••••••••" />
                </div>
              </div>
            ) : (
              <>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Email Address</label>
                  <div className="relative">
                    <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                      <i className="fas fa-envelope"></i>
                    </span>
                    <input name="email" type="email" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="email@domain.com" />
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Mobile Contact</label>
                  <div className="relative">
                    <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                      <i className="fas fa-phone"></i>
                    </span>
                    <input name="mobile" type="tel" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="+1 (555) 000-0000" />
                  </div>
                </div>
              </>
            )}

            <button type="submit" className="w-full bg-slate-900 text-white py-3.5 rounded-xl font-bold hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 flex items-center justify-center gap-2 mt-4">
              {role === 'authority' ? <><i className="fas fa-lock text-sm"></i> Authenticate Session</> : 'Enter Platform'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-center">
          <i className="fas fa-circle-notch animate-spin text-4xl text-indigo-600 mb-4"></i>
          <p className="text-slate-500 font-medium">Syncing with CivicSense Database...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white text-xs">
                <i className="fas fa-landmark"></i>
              </div>
              <span className="font-bold text-lg tracking-tight text-slate-900">CivicSense</span>
              <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${user?.role === 'authority' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-green-50 text-green-600 border-green-100'}`}>
                {user?.role.toUpperCase()}
              </span>
            </div>
            <div className="flex items-center gap-6">
              <div className="hidden md:flex flex-col items-end">
                <p className="text-sm font-bold text-slate-900">{user?.username}</p>
                <p className="text-[10px] text-slate-400 font-medium tracking-wider uppercase">{user?.role === 'authority' ? 'Officer Terminal' : 'Citizen Access'}</p>
              </div>
              <button onClick={handleLogout} className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-600 rounded-lg transition-all">
                <i className="fas fa-power-off text-lg"></i>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 flex-grow">
        {user?.role === 'citizen' ? (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className="lg:col-span-4">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-24">
                <h2 className="text-xl font-bold mb-6 flex items-center gap-3 text-slate-800">
                  <span className="w-8 h-8 bg-indigo-100 rounded-lg flex items-center justify-center text-indigo-600">
                    <i className="fas fa-bullhorn text-sm"></i>
                  </span>
                  Lodge Report
                </h2>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5">Category</label>
                    <select name="category" className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5">Observation Details</label>
                    <textarea name="description" required rows={3} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="Provide clear details..."></textarea>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5">Location Landmark</label>
                    <input name="location" required className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm" placeholder="Area, Ward, or Street Name" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1.5">Visual Evidence</label>
                    <div className="border-2 border-dashed border-slate-200 bg-slate-50 rounded-xl p-6 text-center hover:bg-white hover:border-indigo-400 transition-all cursor-pointer relative group">
                      <input type="file" name="media" accept="image/*,video/*" required className="absolute inset-0 opacity-0 cursor-pointer" />
                      <i className="fas fa-camera text-slate-300 text-3xl mb-2 group-hover:text-indigo-400 transition-colors"></i>
                      <p className="text-xs text-slate-500 font-medium">Capture or Upload Media</p>
                    </div>
                  </div>
                  <button 
                    disabled={isUploading}
                    className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all transform active:scale-95 ${isUploading ? 'bg-slate-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}
                  >
                    {isUploading ? (
                      <span className="flex items-center justify-center gap-2">
                        <i className="fas fa-atom animate-spin"></i> AI Scanning...
                      </span>
                    ) : 'Transmit Report'}
                  </button>
                </form>
              </div>
            </div>

            <div className="lg:col-span-8 space-y-6">
              <h2 className="text-xl font-bold text-slate-800">Your Incident Timeline</h2>

              {reports.filter(r => r.citizenId === user.id).length === 0 ? (
                <div className="bg-white p-16 rounded-3xl text-center border border-slate-200 shadow-sm">
                  <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <i className="fas fa-file-invoice text-4xl text-slate-200"></i>
                  </div>
                  <h3 className="text-lg font-bold text-slate-900 mb-2">No Reports Yet</h3>
                  <p className="text-slate-500 text-sm max-w-xs mx-auto">Reports submitted will appear here with live tracking.</p>
                </div>
              ) : (
                reports.filter(r => r.citizenId === user.id).map(report => (
                  <div key={report.id} className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-all">
                    <div className="p-8">
                      <div className="flex flex-col sm:flex-row justify-between items-start gap-4 mb-6">
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-2">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-extrabold uppercase tracking-widest ${
                              report.status === ReportStatus.RESOLVED ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {report.status}
                            </span>
                            <span className="text-xs font-bold text-indigo-600 uppercase">{report.category}</span>
                          </div>
                          <h3 className="text-xl font-bold text-slate-900 leading-tight">{report.description}</h3>
                          <p className="text-xs text-slate-400 flex items-center gap-2 mt-2">
                            <i className="fas fa-map-marker-alt text-red-400"></i> {report.location} • <i className="fas fa-calendar-alt"></i> {new Date(report.timestamp).toDateString()}
                          </p>
                        </div>
                        {report.status === ReportStatus.RESOLVED && (
                          <div className="w-12 h-12 bg-emerald-100 rounded-full flex items-center justify-center text-emerald-600 animate-bounce">
                            <i className="fas fa-check"></i>
                          </div>
                        )}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="group relative rounded-2xl overflow-hidden bg-slate-100 border border-slate-200 aspect-video shadow-inner">
                          {report.mediaType === 'image' ? (
                            <img src={report.mediaUrl} className="w-full h-full object-cover transition-transform group-hover:scale-105" alt="Proof" />
                          ) : (
                            <video src={report.mediaUrl} className="w-full h-full object-cover" controls />
                          )}
                        </div>
                        <div className="bg-indigo-50/30 p-5 rounded-2xl border border-indigo-100/50">
                          <h4 className="text-[10px] font-extrabold text-indigo-400 uppercase tracking-widest mb-3">AI System Notes</h4>
                          <p className="text-sm text-indigo-900/80 font-medium leading-relaxed italic">"{report.aiAnalysis}"</p>
                        </div>
                      </div>

                      {report.status === ReportStatus.RESOLVED && (
                        <div className="mt-8 pt-8 border-t border-slate-100 bg-emerald-50/20 -mx-8 px-8 -mb-8 pb-8">
                          <h4 className="text-sm font-extrabold text-emerald-800 mb-4 flex items-center gap-3">
                            <i className="fas fa-hard-hat text-xs"></i>
                            Closure Evidence
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-center">
                             {report.workDoneMediaUrl && (
                                <div className="rounded-2xl aspect-video overflow-hidden border-2 border-emerald-100 shadow-lg">
                                  <img src={report.workDoneMediaUrl} className="w-full h-full object-cover" alt="Closure Proof" />
                                </div>
                             )}
                             <div>
                                <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-1">Official Resolution</p>
                                <p className="text-sm text-slate-700 font-medium leading-relaxed">{report.workDoneDescription}</p>
                                <p className="text-[10px] text-slate-400 mt-4 uppercase">Resolved at {new Date(report.resolvedAt!).toLocaleString()}</p>
                             </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Analytics Dashboard */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {[
                { label: 'Cloud Total', val: stats.total, icon: 'fa-database', color: 'bg-indigo-500' },
                { label: 'Pending Action', val: stats.pending, icon: 'fa-clock', color: 'bg-amber-500' },
                { label: 'Resolved Cases', val: stats.resolved, icon: 'fa-check-circle', color: 'bg-emerald-500' },
                { label: 'Sync Status', val: 'Online', icon: 'fa-wifi', color: 'bg-blue-500' }
              ].map((card, i) => (
                <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200 flex items-center gap-5">
                  <div className={`w-12 h-12 ${card.color} rounded-2xl flex items-center justify-center text-white shadow-lg`}>
                    <i className={`fas ${card.icon}`}></i>
                  </div>
                  <div>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{card.label}</p>
                    <p className="text-2xl font-black text-slate-900 leading-tight">{card.val}</p>
                  </div>
                </div>
              ))}
            </div>

            {/* Authority Workspace */}
            <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-8 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center bg-slate-50/50 gap-4">
                <div>
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight">Governance Workspace</h2>
                  <p className="text-slate-500 text-sm font-medium">Real-time sync from Supabase</p>
                </div>
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-bold border border-emerald-100 flex items-center gap-2">
                    <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                    Terminal Sync: Active
                  </div>
                </div>
              </div>

              <div className="divide-y divide-slate-100">
                {reports.length === 0 ? (
                  <div className="p-32 text-center text-slate-400 font-bold uppercase text-xs tracking-widest">
                    No active reports in cloud
                  </div>
                ) : (
                  reports.map(report => (
                    <div key={report.id} className="p-8 hover:bg-slate-50/30 transition-all duration-300">
                      <div className="flex flex-col lg:flex-row gap-10">
                        <div className="flex-1">
                          <div className="flex flex-wrap items-center gap-3 mb-4">
                            <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest shadow-sm ${
                              report.status === ReportStatus.RESOLVED ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'
                            }`}>
                              {report.status}
                            </span>
                            <span className="text-xs font-black text-indigo-600 uppercase bg-indigo-50 px-3 py-1 rounded-lg border border-indigo-100">{report.category}</span>
                            <span className="text-[10px] font-bold text-slate-400 ml-auto">DB REF: {report.id.slice(0, 8)}</span>
                          </div>

                          <h3 className="text-xl font-black text-slate-900 mb-3">{report.description}</h3>

                          <div className="flex flex-wrap items-center gap-6 text-xs font-bold text-slate-400 mb-8 border-y border-slate-50 py-3">
                            <span><i className="fas fa-user-circle text-indigo-400"></i> {report.citizenName}</span>
                            <span><i className="fas fa-map-pin text-red-400"></i> {report.location}</span>
                            <span><i className="fas fa-history"></i> {new Date(report.timestamp).toLocaleString()}</span>
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="aspect-video rounded-3xl bg-slate-100 overflow-hidden border border-slate-200 shadow-lg">
                              {report.mediaType === 'image' ? (
                                <img src={report.mediaUrl} className="w-full h-full object-cover" alt="Issue Evidence" />
                              ) : (
                                <video src={report.mediaUrl} className="w-full h-full object-cover" controls />
                              )}
                            </div>
                            <div className="p-6 bg-slate-900 rounded-3xl border border-slate-800 shadow-xl">
                              <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-4">AI Cloud Assessment</p>
                              <p className="text-sm text-slate-200 font-medium leading-relaxed italic line-clamp-4">"{report.aiAnalysis}"</p>
                            </div>
                          </div>
                        </div>

                        <div className="lg:w-96 bg-slate-50 p-8 rounded-[2rem] border-2 border-slate-100 shadow-inner h-fit lg:sticky lg:top-24">
                          {report.status === ReportStatus.RESOLVED ? (
                            <div className="text-center py-6">
                              <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center text-emerald-600 mx-auto mb-4">
                                <i className="fas fa-check-double text-2xl"></i>
                              </div>
                              <h4 className="text-lg font-black text-slate-900">Task Disposed</h4>
                              <p className="text-xs text-slate-500 mt-2 font-medium">Record archived and synchronized.</p>
                            </div>
                          ) : (
                            <form 
                              className="space-y-5"
                              onSubmit={(e) => {
                                e.preventDefault();
                                const fd = new FormData(e.currentTarget);
                                resolveReport(report.id, fd.get('res_desc') as string, fd.get('res_media') as File);
                              }}
                            >
                              <h4 className="text-sm font-black text-slate-900 uppercase tracking-wider">Cloud Resolution</h4>
                              <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Internal Log</label>
                                <textarea name="res_desc" required className="w-full text-sm p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none bg-white min-h-[100px]" placeholder="Action taken..."></textarea>
                              </div>
                              <div>
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Final Verification Proof</label>
                                <input name="res_media" type="file" accept="image/*" required className="text-xs w-full block" />
                              </div>
                              <button className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 shadow-xl shadow-slate-200 active:scale-95">
                                Finalize & Notify Reporter
                              </button>
                            </form>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="py-10 text-center border-t border-slate-100 bg-white">
        <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Supabase Integrated • CivicSense v5.0</p>
      </footer>
    </div>
  );
}

export enum ReportStatus {
  PENDING = 'PENDING',
  IN_PROGRESS = 'IN_PROGRESS',
  RESOLVED = 'RESOLVED',
  REJECTED = 'REJECTED'
}

export enum ReportCategory {
  GARBAGE = 'Garbage Dumping',
  WATER_LEAKAGE = 'Water Leakage',
  TREE_CUTTING = 'Illegal Tree Cutting',
  SMUGGLING = 'Smuggling Activity',
  POTHOLES = 'Potholes/Road Damage',
  OTHER = 'Other'
}

export interface User {
  id: string;
  username: string;
  email: string;
  mobile: string;
  role: 'citizen' | 'authority';
}

export interface Report {
  id: string;
  citizen_id: string;
  citizen_name: string;
  title: string;
  description: string;
  category: ReportCategory;
  location: string;
  timestamp: number;
  status: ReportStatus;
  media_url: string;
  media_type: 'image' | 'video';
  ai_analysis?: string;
  work_done_media_url?: string;
  work_done_description?: string;
  resolved_at?: number;
  notified: boolean;
}

export interface AuthoritySession {
  username: string;
  last_active: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status === ReportStatus.PENDING || r.status === ReportStatus.IN_PROGRESS).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .order('timestamp', { ascending: false });

      if (!error && data) {
        setReports(data as Report[]);
      }
      setIsLoading(false);
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const email = formData.get('email') as string;
    const mobile = formData.get('mobile') as string;

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error.");
        return;
      }

      if (sessions.length >= 5 && !sessions.find(s => s.username === username)) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });
    }

    const newUser: User = {
      id: role === 'authority' ? 'auth_atharv' : `cit_${Math.random().toString(36).substr(2, 9)}`,
      username,
      email: email || (role === 'authority' ? 'authority@civicsense.gov' : ''),
      mobile: mobile || '',
      role: role
    };

    await supabase.from('users').upsert({
      id: newUser.id,
      username: newUser.username,
      email: newUser.email,
      mobile: newUser.mobile,
      role: newUser.role
    });

    setUser(newUser);
    setView('dashboard');
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg shadow-indigo-200 transform rotate-3">
              <i className="fas fa-landmark text-2xl"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
            <p className="text-slate-500 text-sm mt-1">Smart Governance Terminal</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => setRole('citizen')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen Login
            </button>
            <button 
              onClick={() => setRole('authority')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority Login
            </button>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
              <input 
                name="username" required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none" 
                placeholder="Enter username" 
              />
            </div>

            {role === 'authority' ? (
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Passcode</label>
                <input 
                  name="password" type="password" required
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none" 
                  placeholder="••••••••" 
                />
              </div>
            ) : (
              <>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email</label>
                  <input 
                    name="email" type="email" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none" 
                    placeholder="name@example.com" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No.</label>
                  <input 
                    name="mobile" type="tel" required
