import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Root element not found");

const root = createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      // Upsert authority session
      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });
    }

    const userId = role === 'authority' ? `auth_${username}` : `cit_${Math.random().toString(36).substr(2, 9)}`;
    const newUser: User = {
      id: userId,
      username,
      email: email || (role === 'authority' ? 'authority@civicsense.gov' : ''),
      mobile,
      role
    };

    // Store user info
    await supabase.from('users').upsert({
      id: newUser.id,
      username: newUser.username,
      email: newUser.email,
      mobile: newUser.mobile,
      role: newUser.role
    });

    setUser(newUser);
    setView('dashboard');
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg shadow-indigo-200 transform rotate-3">
              <i className="fas fa-landmark text-2xl"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
            <p className="text-slate-500 text-sm mt-1">Smart Governance Portal</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => setRole('citizen')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen
            </button>
            <button 
              onClick={() => setRole('authority')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority
            </button>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
              <input 
                name="username" required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                placeholder="Name" 
              />
            </div>

            {role === 'authority' ? (
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Passcode</label>
                <input 
                  name="password" type="password" required
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                  placeholder="••••••••" 
                />
              </div>
            ) : (
              <>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email</label>
                  <input 
                    name="email" type="email" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="email@example.com" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No.</label>
                  <input 
                    name="mobile" type="tel" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="+91 00000 00000" 
                  />
                </div>
              </>
            )}

            <button 
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] mt-4"
            >
              Login <i className="fas fa-arrow-right ml-2 text-sm opacity-50"></i>
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-md">
              <i className="fas fa-landmark"></i>
            </div>
            <h2 className="font-bold text-slate-900 hidden sm:block">CivicSense</h2>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-sm font-semibold text-slate-900 capitalize">{user?.username}</p>
              <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">{user?.role}</p>
            </div>
            <button 
              onClick={handleLogout}
              className="p-2.5 rounded-xl text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
            >
              <i className="fas fa-sign-out-alt"></i>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">
        {user?.role === 'citizen' ? (
          <>
            {/* Citizen Submit */}
            <div className="lg:col-span-4 space-y-6">
              <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-indigo-600">
                  <i className="fas fa-plus-circle"></i>
                  File New Report
                </h3>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                    <select name="category" required className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                    <textarea 
                      name="description" required rows={3}
                      placeholder="Briefly explain the issue..."
                      className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500"
                    ></textarea>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Location</label>
                    <input name="location" required placeholder="Where is it?" className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Evidence</label>
                    <input name="media" type="file" accept="image/*,video/*" required className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:bg-indigo-50 file:text-indigo-700" />
                  </div>
                  <button 
                    disabled={isUploading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {isUploading ? <i className="fas fa-spinner animate-spin"></i> : <><i className="fas fa-paper-plane"></i> Submit</>}
                  </button>
                </form>
              </section>
            </div>

            {/* Citizen Feed */}
            <div className="lg:col-span-8 space-y-4">
              <h3 className="font-bold text-xl text-slate-900">Community Reports</h3>
              {reports.length === 0 && !isLoading && <p className="text-slate-500 italic">No reports found.</p>}
              {reports.map(report => (
                <div key={report.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm flex flex-col md:flex-row">
                  <div className="md:w-48 h-48 bg-slate-100 flex-shrink-0">
                    {report.media_type === 'video' ? (
                      <video src={report.media_url} controls className="w-full h-full object-cover" />
                    ) : (
                      <img src={report.media_url} alt="Evidence" className="w-full h-full object-cover" />
                    )}
                  </div>
                  <div className="p-5 flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <span className={`px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider ${
                        report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {report.status}
                      </span>
                      <span className="text-[10px] text-slate-400 font-medium">
                        {new Date(report.timestamp).toLocaleDateString()}
                      </span>
                    </div>
                    <h4 className="font-bold text-lg text-slate-900 mb-1">{report.title}</h4>
                    <p className="text-slate-500 text-sm mb-3">📍 {report.location}</p>
                    <p className="text-slate-600 text-sm mb-4">"{report.description}"</p>

                    {report.status === ReportStatus.RESOLVED && (
                      <div className="mt-4 pt-4 border-t border-slate-100 flex items-center gap-4 text-green-600">
                        <i className="fas fa-check-circle text-xl"></i>
                        <div className="text-xs font-semibold">
                          Resolved: {report.work_done_description}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          /* Authority Dashboard */
          <div className="lg:col-span-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Total</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.total}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-amber-500 uppercase mb-2">Pending</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.pending}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-green-500 uppercase mb-2">Resolved</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.resolved}</span>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">Report</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {reports.map(report => (
                    <tr key={report.id} className="hover:bg-slate-50/50">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <img src={report.media_url} className="w-10 h-10 rounded-lg object-cover" />
                          <div>
                            <p className="text-sm font-bold text-slate-900">{report.title}</p>
                            <p className="text-[10px] text-slate-500">{report.citizen_name}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${
                          report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'
                        }`}>
                          {report.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {report.status !== ReportStatus.RESOLVED ? (
                          <button 
                            onClick={() => setResolvingId(report.id)}
                            className="text-xs font-bold text-indigo-600 hover:underline"
                          >
                            Mark Resolved
                          </button>
                        ) : <span className="text-xs text-slate-400">Fixed</span>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Resolution Modal */}
      {resolvingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <h3 className="font-bold text-slate-900">Upload Resolution Proof</h3>
              <button onClick={() => setResolvingId(null)}><i className="fas fa-times text-slate-400"></i></button>
            </div>
            <form onSubmit={handleResolve} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Work Description</label>
                <textarea name="resolution" required rows={4} className="w-full p-3 rounded-xl border border-slate-200" placeholder="What was done?"></textarea>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proof Photo</label>
                <input name="work_media" type="file" accept="image/*" required className="w-full text-sm" />
              </div>
              <button disabled={isUploading} className="w-full py-3 bg-green-600 text-white rounded-xl font-bold shadow-lg disabled:opacity-50">
                {isUploading ? "Uploading..." : "Complete Task"}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleAuth = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });

      const newUser: User = {
        id: `auth_${username}`,
        username,
        email: 'authority@civicsense.gov',
        mobile: '',
        role: 'authority'
      };
      setUser(newUser);
      setView('dashboard');
      return;
    }

    // Citizen Logic
    if (isSignUp) {
      if (password !== confirmPassword) {
        alert("Passwords do not match!");
        return;
      }

      // Check if user exists
      const { data: existingUser } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .single();

      if (existingUser) {
        alert("Username already taken. Please sign in.");
        setIsSignUp(false);
        return;
      }

      const userId = `cit_${Math.random().toString(36).substr(2, 9)}`;
      const { error: signUpError } = await supabase.from('users').insert({
        id: userId,
        username,
        password, // In a real app, hash this!
        email,
        mobile,
        role: 'citizen'
      });

      if (signUpError) {
        alert("Error signing up: " + signUpError.message);
        return;
      }

      alert("Account created successfully! Please sign in.");
      setIsSignUp(false);
    } else {
      // Sign In Logic
      const { data: userData, error: signInError } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (signInError || !userData) {
        alert("Invalid username or password.");
        return;
      }

      setUser(userData as User);
      setView('dashboard');
    }
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
    setIsSignUp(false);
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg shadow-indigo-200 transform rotate-3 transition-transform hover:rotate-0">
              <i className="fas fa-landmark text-2xl"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
            <p className="text-slate-500 text-sm mt-1">Smart Governance Portal</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => { setRole('citizen'); setIsSignUp(false); }}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Citizen
            </button>
            <button 
              onClick={() => { setRole('authority'); setIsSignUp(false); }}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Authority
            </button>
          </div>

          <form onSubmit={handleAuth} className="space-y-4">
            <h2 className="text-xl font-bold text-slate-800 mb-2">
              {role === 'authority' ? 'Authority Login' : (isSignUp ? 'Create Citizen Account' : 'Citizen Sign In')}
            </h2>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
              <input 
                name="username" required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                placeholder="Unique username" 
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Password</label>
              <input 
                name="password" type="password" required
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                placeholder="••••••••" 
              />
            </div>

            {role === 'citizen' && isSignUp && (
              <>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm Password</label>
                  <input 
                    name="confirmPassword" type="password" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="••••••••" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email (Optional)</label>
                  <input 
                    name="email" type="email"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="email@example.com" 
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No. (Optional)</label>
                  <input 
                    name="mobile" type="tel"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="+91 00000 00000" 
                  />
                </div>
              </>
            )}

            <button 
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] mt-4"
            >
              {role === 'authority' || !isSignUp ? 'Login' : 'Sign Up'} <i className="fas fa-arrow-right ml-2 text-sm opacity-50"></i>
            </button>

            {role === 'citizen' && (
              <div className="text-center mt-4">
                <button 
                  type="button"
                  onClick={() => setIsSignUp(!isSignUp)}
                  className="text-sm font-semibold text-indigo-600 hover:text-indigo-800 transition-colors"
                >
                  {isSignUp ? 'Already have an account? Sign In' : "Don't have an account? Sign Up"}
                </button>
              </div>
            )}
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-md">
              <i className="fas fa-landmark"></i>
            </div>
            <h2 className="font-bold text-slate-900 hidden sm:block">CivicSense</h2>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-sm font-semibold text-slate-900 capitalize">{user?.username}</p>
              <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">{user?.role}</p>
            </div>
            <button 
              onClick={handleLogout}
              className="p-2.5 rounded-xl text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
            >
              <i className="fas fa-sign-out-alt"></i>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">
        {user?.role === 'citizen' ? (
          <>
            {/* Citizen Submit */}
            <div className="lg:col-span-4 space-y-6">
              <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-indigo-600">
                  <i className="fas fa-plus-circle"></i>
                  File New Report
                </h3>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                    <select name="category" required className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                    <textarea 
                      name="description" required rows={3}
                      placeholder="Briefly explain the issue..."
                      className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500"
                    ></textarea>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Location</label>
                    <input name="location" required placeholder="Where is it?" className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Evidence</label>
                    <input name="media" type="file" accept="image/*,video/*" required className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:bg-indigo-50 file:text-indigo-700" />
                  </div>
                  <button 
                    disabled={isUploading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {isUploading ? <i className="fas fa-spinner animate-spin"></i> : <><i className="fas fa-paper-plane"></i> Submit</>}
                  </button>
                </form>
              </section>
            </div>

            {/* Citizen Feed */}
            <div className="lg:col-span-8 space-y-4">
              <h3 className="font-bold text-xl text-slate-900">Community Reports</h3>
              {reports.length === 0 && !isLoading && <p className="text-slate-500 italic">No reports found.</p>}
              {reports.map(report => (
                <div key={report.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm flex flex-col md:flex-row">
                  <div className="md:w-48 h-48 bg-slate-100 flex-shrink-0">
                    {report.media_type === 'video' ? (
                      <video src={report.media_url} controls className="w-full h-full object-cover" />
                    ) : (
                      <img src={report.media_url} alt="Evidence" className="w-full h-full object-cover" />
                    )}
                  </div>
                  <div className="p-5 flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <span className={`px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider ${
                        report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {report.status}
                      </span>
                      <span className="text-[10px] text-slate-400 font-medium">
                        {new Date(report.timestamp).toLocaleDateString()}
                      </span>
                    </div>
                    <h4 className="font-bold text-lg text-slate-900 mb-1">{report.title}</h4>
                    <p className="text-slate-500 text-sm mb-3">📍 {report.location}</p>
                    <p className="text-slate-600 text-sm mb-4">"{report.description}"</p>

                    {report.status === ReportStatus.RESOLVED && (
                      <div className="mt-4 pt-4 border-t border-slate-100 flex items-center gap-4 text-green-600">
                        <i className="fas fa-check-circle text-xl"></i>
                        <div className="text-xs font-semibold">
                          Resolved: {report.work_done_description}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          /* Authority Dashboard */
          <div className="lg:col-span-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Total</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.total}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-amber-500 uppercase mb-2">Pending</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.pending}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-green-500 uppercase mb-2">Resolved</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.resolved}</span>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">Report</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {reports.map(report => (
                    <tr key={report.id} className="hover:bg-slate-50/50">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <img src={report.media_url} className="w-10 h-10 rounded-lg object-cover" />
                          <div>
                            <p className="text-sm font-bold text-slate-900">{report.title}</p>
                            <p className="text-[10px] text-slate-500">{report.citizen_name}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${
                          report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'
                        }`}>
                          {report.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {report.status !== ReportStatus.RESOLVED ? (
                          <button 
                            onClick={() => setResolvingId(report.id)}
                            className="text-xs font-bold text-indigo-600 hover:underline"
                          >
                            Mark Resolved
                          </button>
                        ) : <span className="text-xs text-slate-400">Fixed</span>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Resolution Modal */}
      {resolvingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <h3 className="font-bold text-slate-900">Upload Resolution Proof</h3>
              <button onClick={() => setResolvingId(null)}><i className="fas fa-times text-slate-400"></i></button>
            </div>
            <form onSubmit={handleResolve} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Work Description</label>
                <textarea name="resolution" required rows={4} className="w-full p-3 rounded-xl border border-slate-200" placeholder="What was done?"></textarea>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proof Photo</label>
                <input name="work_media" type="file" accept="image/*" required className="w-full text-sm" />
              </div>
              <button disabled={isUploading} className="w-full py-3 bg-green-600 text-white rounded-xl font-bold shadow-lg disabled:opacity-50">
                {isUploading ? "Uploading..." : "Complete Task"}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);

  // Forgot Password State
  const [forgotPasswordStep, setForgotPasswordStep] = useState<'none' | 'identify' | 'otp' | 'reset'>('none');
  const [resetTargetUser, setResetTargetUser] = useState<any>(null);
  const [generatedOtp, setGeneratedOtp] = useState<string>('');
  const [enteredOtp, setEnteredOtp] = useState<string>('');

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleAuth = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });

      const newUser: User = {
        id: `auth_${username}`,
        username,
        email: 'authority@civicsense.gov',
        mobile: '',
        role: 'authority'
      };
      setUser(newUser);
      setView('dashboard');
      return;
    }

    // Citizen Logic
    if (isSignUp) {
      if (password !== confirmPassword) {
        alert("Passwords do not match!");
        return;
      }

      // Check if user exists
      const { data: existingUser } = await supabase
        .from('users')
        .select('*')
        .or(`username.eq.${username},email.eq.${email}`)
        .single();

      if (existingUser) {
        alert("Username or Email already exists. Please sign in.");
        setIsSignUp(false);
        return;
      }

      const userId = `cit_${Math.random().toString(36).substr(2, 9)}`;
      const { error: signUpError } = await supabase.from('users').insert({
        id: userId,
        username,
        password, // Note: In production use hashing
        email,
        mobile,
        role: 'citizen'
      });

      if (signUpError) {
        alert("Error signing up: " + signUpError.message);
        return;
      }

      alert("Account created successfully! Please sign in.");
      setIsSignUp(false);
    } else {
      // Sign In Logic
      const { data: userData, error: signInError } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (signInError || !userData) {
        alert("Invalid username or password.");
        return;
      }

      setUser(userData as User);
      setView('dashboard');
    }
  };

  const initiateForgotPassword = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const identifier = new FormData(e.currentTarget).get('identifier') as string;

    // Find user by username or email
    const { data: userData, error } = await supabase
      .from('users')
      .select('*')
      .or(`username.eq.${identifier},email.eq.${identifier}`)
      .single();

    if (error || !userData) {
      alert("No user found with that detail.");
      return;
    }

    // Simulate sending OTP
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(otp);
    setResetTargetUser(userData);
    setForgotPasswordStep('otp');

    // Show user the "sent" location
    const mask = (str: string) => str.slice(0, 3) + '***' + str.slice(-2);
    alert(`A 6-digit OTP has been sent to ${mask(userData.email)} and ${mask(userData.mobile)}.\n(Demo OTP: ${otp})`);
  };

  const verifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (enteredOtp === generatedOtp) {
      setForgotPasswordStep('reset');
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  const finalizeReset = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newPass = formData.get('newPassword') as string;
    const confirmPass = formData.get('confirmNewPassword') as string;

    if (newPass !== confirmPass) {
      alert("Passwords do not match.");
      return;
    }

    const { error } = await supabase
      .from('users')
      .update({ password: newPass })
      .eq('id', resetTargetUser.id);

    if (error) {
      alert("Failed to update password.");
    } else {
      alert("Password updated successfully. You can now login.");
      setForgotPasswordStep('none');
      setResetTargetUser(null);
    }
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
    setIsSignUp(false);
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          {forgotPasswordStep === 'none' ? (
            <>
              <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg transform rotate-3 transition-transform hover:rotate-0">
                  <i className="fas fa-landmark text-2xl"></i>
                </div>
                <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
                <p className="text-slate-500 text-sm mt-1">Smart Governance Portal</p>
              </div>

              <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
                <button 
                  onClick={() => { setRole('citizen'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Citizen
                </button>
                <button 
                  onClick={() => { setRole('authority'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Authority
                </button>
              </div>

              <form onSubmit={handleAuth} className="space-y-4">
                <h2 className="text-xl font-bold text-slate-800 mb-2">
                  {role === 'authority' ? 'Authority Access' : (isSignUp ? 'Join Community' : 'Welcome Back')}
                </h2>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
                  <input 
                    name="username" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="Enter username" 
                  />
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Password</label>
                  <input 
                    name="password" type="password" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="••••••••" 
                  />
                </div>

                {role === 'citizen' && isSignUp && (
                  <>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm Password</label>
                      <input 
                        name="confirmPassword" type="password" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="••••••••" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email <span className="text-red-500">*</span></label>
                      <input 
                        name="email" type="email" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="email@example.com" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No. <span className="text-red-500">*</span></label>
                      <input 
                        name="mobile" type="tel" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="+91 00000 00000" 
                      />
                    </div>
                  </>
                )}

                {!isSignUp && role === 'citizen' && (
                  <div className="flex justify-end">
                    <button 
                      type="button" 
                      onClick={() => setForgotPasswordStep('identify')}
                      className="text-xs font-semibold text-indigo-500 hover:text-indigo-700"
                    >
                      Forgot Password?
                    </button>
                  </div>
                )}

                <button 
                  type="submit"
                  className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] mt-4"
                >
                  {role === 'authority' || !isSignUp ? 'Login' : 'Create Account'} <i className="fas fa-arrow-right ml-2 text-sm opacity-50"></i>
                </button>

                {role === 'citizen' && (
                  <div className="text-center mt-4">
                    <button 
                      type="button"
                      onClick={() => setIsSignUp(!isSignUp)}
                      className="text-sm font-semibold text-indigo-600 hover:text-indigo-800 transition-colors"
                    >
                      {isSignUp ? 'Already have an account? Sign In' : "Don't have an account? Sign Up"}
                    </button>
                  </div>
                )}
              </form>
            </>
          ) : (
            <div className="space-y-6">
              <div className="text-center">
                <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-key text-xl"></i>
                </div>
                <h2 className="text-2xl font-bold text-slate-800">Reset Password</h2>
                <p className="text-slate-500 text-sm mt-1">
                  {forgotPasswordStep === 'identify' && "Enter your username or email to find your account."}
                  {forgotPasswordStep === 'otp' && "Enter the 6-digit OTP sent to your registered contact."}
                  {forgotPasswordStep === 'reset' && "Enter your new secure password below."}
                </p>
              </div>

              {forgotPasswordStep === 'identify' && (
                <form onSubmit={initiateForgotPassword} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Account Identifier</label>
                    <input name="identifier" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Username or Email" />
                  </div>
                  <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-indigo-700">Find Account</button>
                </form>
              )}

              {forgotPasswordStep === 'otp' && (
                <form onSubmit={verifyOtp} className="space-y-4 text-center">
                  <div className="flex justify-center gap-2">
                    <input 
                      maxLength={6}
                      value={enteredOtp}
                      onChange={(e) => setEnteredOtp(e.target.value.replace(/\D/g, ''))}
                      className="w-full tracking-[1rem] text-center text-2xl font-bold px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" 
                      placeholder="000000" 
                    />
                  </div>
                  <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-indigo-700">Verify OTP</button>
                </form>
              )}

              {forgotPasswordStep === 'reset' && (
                <form onSubmit={finalizeReset} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">New Password</label>
                    <input name="newPassword" type="password" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm New Password</label>
                    <input name="confirmNewPassword" type="password" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <button type="submit" className="w-full bg-green-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-green-700">Save Password</button>
                </form>
              )}

              <button 
                onClick={() => { setForgotPasswordStep('none'); setEnteredOtp(''); }}
                className="w-full text-slate-400 hover:text-slate-600 text-sm font-medium"
              >
                Cancel and Return
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-md">
              <i className="fas fa-landmark"></i>
            </div>
            <h2 className="font-bold text-slate-900 hidden sm:block">CivicSense</h2>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-sm font-semibold text-slate-900 capitalize">{user?.username}</p>
              <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">{user?.role}</p>
            </div>
            <button 
              onClick={handleLogout}
              className="p-2.5 rounded-xl text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
            >
              <i className="fas fa-sign-out-alt"></i>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">
        {user?.role === 'citizen' ? (
          <>
            {/* Citizen Submit */}
            <div className="lg:col-span-4 space-y-6">
              <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-indigo-600">
                  <i className="fas fa-plus-circle"></i>
                  File New Report
                </h3>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                    <select name="category" required className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                    <textarea 
                      name="description" required rows={3}
                      placeholder="Briefly explain the issue..."
                      className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500"
                    ></textarea>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Location</label>
                    <input name="location" required placeholder="Where is it?" className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Evidence</label>
                    <input name="media" type="file" accept="image/*,video/*" required className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:bg-indigo-50 file:text-indigo-700" />
                  </div>
                  <button 
                    disabled={isUploading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {isUploading ? <i className="fas fa-spinner animate-spin"></i> : <><i className="fas fa-paper-plane"></i> Submit</>}
                  </button>
                </form>
              </section>
            </div>

            {/* Citizen Feed */}
            <div className="lg:col-span-8 space-y-4">
              <h3 className="font-bold text-xl text-slate-900">Community Reports</h3>
              {reports.length === 0 && !isLoading && <p className="text-slate-500 italic">No reports found.</p>}
              {reports.map(report => (
                <div key={report.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm flex flex-col md:flex-row">
                  <div className="md:w-48 h-48 bg-slate-100 flex-shrink-0">
                    {report.media_type === 'video' ? (
                      <video src={report.media_url} controls className="w-full h-full object-cover" />
                    ) : (
                      <img src={report.media_url} alt="Evidence" className="w-full h-full object-cover" />
                    )}
                  </div>
                  <div className="p-5 flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <span className={`px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider ${
                        report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {report.status}
                      </span>
                      <span className="text-[10px] text-slate-400 font-medium">
                        {new Date(report.timestamp).toLocaleDateString()}
                      </span>
                    </div>
                    <h4 className="font-bold text-lg text-slate-900 mb-1">{report.title}</h4>
                    <p className="text-slate-500 text-sm mb-3">📍 {report.location}</p>
                    <p className="text-slate-600 text-sm mb-4">"{report.description}"</p>

                    {report.status === ReportStatus.RESOLVED && (
                      <div className="mt-4 pt-4 border-t border-slate-100 flex items-center gap-4 text-green-600">
                        <i className="fas fa-check-circle text-xl"></i>
                        <div className="text-xs font-semibold">
                          Resolved: {report.work_done_description}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          /* Authority Dashboard */
          <div className="lg:col-span-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Total</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.total}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-amber-500 uppercase mb-2">Pending</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.pending}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-green-500 uppercase mb-2">Resolved</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.resolved}</span>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">Report</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {reports.map(report => (
                    <tr key={report.id} className="hover:bg-slate-50/50">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <img src={report.media_url} className="w-10 h-10 rounded-lg object-cover" />
                          <div>
                            <p className="text-sm font-bold text-slate-900">{report.title}</p>
                            <p className="text-[10px] text-slate-500">{report.citizen_name}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${
                          report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'
                        }`}>
                          {report.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {report.status !== ReportStatus.RESOLVED ? (
                          <button 
                            onClick={() => setResolvingId(report.id)}
                            className="text-xs font-bold text-indigo-600 hover:underline"
                          >
                            Mark Resolved
                          </button>
                        ) : <span className="text-xs text-slate-400">Fixed</span>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Resolution Modal */}
      {resolvingId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <h3 className="font-bold text-slate-900">Upload Resolution Proof</h3>
              <button onClick={() => setResolvingId(null)}><i className="fas fa-times text-slate-400"></i></button>
            </div>
            <form onSubmit={handleResolve} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Work Description</label>
                <textarea name="resolution" required rows={4} className="w-full p-3 rounded-xl border border-slate-200" placeholder="What was done?"></textarea>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proof Photo</label>
                <input name="work_media" type="file" accept="image/*" required className="w-full text-sm" />
              </div>
              <button disabled={isUploading} className="w-full py-3 bg-green-600 text-white rounded-xl font-bold shadow-lg disabled:opacity-50">
                {isUploading ? "Uploading..." : "Complete Task"}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/gemini';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  // Forgot Password State
  const [forgotPasswordStep, setForgotPasswordStep] = useState<'none' | 'identify' | 'otp' | 'reset'>('none');
  const [resetTargetUser, setResetTargetUser] = useState<any>(null);
  const [generatedOtp, setGeneratedOtp] = useState<string>('');
  const [enteredOtp, setEnteredOtp] = useState<string>('');

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleAuth = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });

      const newUser: User = {
        id: `auth_${username}`,
        username,
        email: 'authority@civicsense.gov',
        mobile: '',
        role: 'authority'
      };
      setUser(newUser);
      setView('dashboard');
      return;
    }

    // Citizen Logic
    if (isSignUp) {
      if (password !== confirmPassword) {
        alert("Passwords do not match!");
        return;
      }

      // Check if user exists
      const { data: existingUser } = await supabase
        .from('users')
        .select('*')
        .or(`username.eq.${username},email.eq.${email}`)
        .single();

      if (existingUser) {
        alert("Username or Email already exists. Please sign in.");
        setIsSignUp(false);
        return;
      }

      const userId = `cit_${Math.random().toString(36).substr(2, 9)}`;
      const { error: signUpError } = await supabase.from('users').insert({
        id: userId,
        username,
        password, 
        email,
        mobile,
        role: 'citizen'
      });

      if (signUpError) {
        alert("Error signing up: " + signUpError.message);
        return;
      }

      alert("Account created successfully! Please sign in.");
      setIsSignUp(false);
    } else {
      // Sign In Logic
      const { data: userData, error: signInError } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (signInError || !userData) {
        alert("Invalid username or password.");
        return;
      }

      setUser(userData as User);
      setView('dashboard');
    }
  };

  const initiateForgotPassword = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const identifier = new FormData(e.currentTarget).get('identifier') as string;

    // Find user by username or email
    const { data: userData, error } = await supabase
      .from('users')
      .select('*')
      .or(`username.eq.${identifier},email.eq.${identifier}`)
      .single();

    if (error || !userData) {
      alert("No user found with that detail.");
      return;
    }

    // Simulate sending OTP
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(otp);
    setResetTargetUser(userData);
    setForgotPasswordStep('otp');

    // Show user the "sent" location
    const mask = (str: string) => str.slice(0, 3) + '***' + str.slice(-2);
    alert(`A 6-digit OTP has been sent to ${mask(userData.email)} and ${mask(userData.mobile)}.\n(Demo OTP: ${otp})`);
  };

  const verifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (enteredOtp === generatedOtp) {
      setForgotPasswordStep('reset');
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  const finalizeReset = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newPass = formData.get('newPassword') as string;
    const confirmPass = formData.get('confirmNewPassword') as string;

    if (newPass !== confirmPass) {
      alert("Passwords do not match.");
      return;
    }

    const { error } = await supabase
      .from('users')
      .update({ password: newPass })
      .eq('id', resetTargetUser.id);

    if (error) {
      alert("Failed to update password.");
    } else {
      alert("Password updated successfully. You can now login.");
      setForgotPasswordStep('none');
      setResetTargetUser(null);
    }
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
    setIsSignUp(false);
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  const viewingReport = useMemo(() => 
    reports.find(r => r.id === viewingReportId), 
    [viewingReportId, reports]
  );

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          {forgotPasswordStep === 'none' ? (
            <>
              <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg transform rotate-3 transition-transform hover:rotate-0">
                  <i className="fas fa-landmark text-2xl"></i>
                </div>
                <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
                <p className="text-slate-500 text-sm mt-1">Smart Governance Portal</p>
              </div>

              <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
                <button 
                  onClick={() => { setRole('citizen'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Citizen
                </button>
                <button 
                  onClick={() => { setRole('authority'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Authority
                </button>
              </div>

              <form onSubmit={handleAuth} className="space-y-4">
                <h2 className="text-xl font-bold text-slate-800 mb-2">
                  {role === 'authority' ? 'Authority Access' : (isSignUp ? 'Join Community' : 'Welcome Back')}
                </h2>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
                  <input 
                    name="username" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="Enter username" 
                  />
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Password</label>
                  <input 
                    name="password" type="password" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="••••••••" 
                  />
                </div>

                {role === 'citizen' && isSignUp && (
                  <>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm Password</label>
                      <input 
                        name="confirmPassword" type="password" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="••••••••" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email <span className="text-red-500">*</span></label>
                      <input 
                        name="email" type="email" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="email@example.com" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No. <span className="text-red-500">*</span></label>
                      <input 
                        name="mobile" type="tel" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="+91 00000 00000" 
                      />
                    </div>
                  </>
                )}

                {!isSignUp && role === 'citizen' && (
                  <div className="flex justify-end">
                    <button 
                      type="button" 
                      onClick={() => setForgotPasswordStep('identify')}
                      className="text-xs font-semibold text-indigo-500 hover:text-indigo-700"
                    >
                      Forgot Password?
                    </button>
                  </div>
                )}

                <button 
                  type="submit"
                  className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] mt-4"
                >
                  {role === 'authority' || !isSignUp ? 'Login' : 'Create Account'} <i className="fas fa-arrow-right ml-2 text-sm opacity-50"></i>
                </button>

                {role === 'citizen' && (
                  <div className="text-center mt-4">
                    <button 
                      type="button"
                      onClick={() => setIsSignUp(!isSignUp)}
                      className="text-sm font-semibold text-indigo-600 hover:text-indigo-800 transition-colors"
                    >
                      {isSignUp ? 'Already have an account? Sign In' : "Don't have an account? Sign Up"}
                    </button>
                  </div>
                )}
              </form>
            </>
          ) : (
            <div className="space-y-6">
              <div className="text-center">
                <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-key text-xl"></i>
                </div>
                <h2 className="text-2xl font-bold text-slate-800">Reset Password</h2>
                <p className="text-slate-500 text-sm mt-1">
                  {forgotPasswordStep === 'identify' && "Enter your username or email to find your account."}
                  {forgotPasswordStep === 'otp' && "Enter the 6-digit OTP sent to your registered contact."}
                  {forgotPasswordStep === 'reset' && "Enter your new secure password below."}
                </p>
              </div>

              {forgotPasswordStep === 'identify' && (
                <form onSubmit={initiateForgotPassword} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Account Identifier</label>
                    <input name="identifier" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Username or Email" />
                  </div>
                  <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-indigo-700">Find Account</button>
                </form>
              )}

              {forgotPasswordStep === 'otp' && (
                <form onSubmit={verifyOtp} className="space-y-4 text-center">
                  <div className="flex justify-center gap-2">
                    <input 
                      maxLength={6}
                      value={enteredOtp}
                      onChange={(e) => setEnteredOtp(e.target.value.replace(/\D/g, ''))}
                      className="w-full tracking-[1rem] text-center text-2xl font-bold px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" 
                      placeholder="000000" 
                    />
                  </div>
                  <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-indigo-700">Verify OTP</button>
                </form>
              )}

              {forgotPasswordStep === 'reset' && (
                <form onSubmit={finalizeReset} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">New Password</label>
                    <input name="newPassword" type="password" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm New Password</label>
                    <input name="confirmNewPassword" type="password" required className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <button type="submit" className="w-full bg-green-600 text-white font-bold py-3 rounded-xl shadow-md hover:bg-green-700">Save Password</button>
                </form>
              )}

              <button 
                onClick={() => { setForgotPasswordStep('none'); setEnteredOtp(''); }}
                className="w-full text-slate-400 hover:text-slate-600 text-sm font-medium"
              >
                Cancel and Return
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-md">
              <i className="fas fa-landmark"></i>
            </div>
            <h2 className="font-bold text-slate-900 hidden sm:block">CivicSense</h2>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-sm font-semibold text-slate-900 capitalize">{user?.username}</p>
              <p className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">{user?.role}</p>
