            >
              <i className="fas fa-sign-out-alt"></i>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">
        {user?.role === 'citizen' ? (
          <>
            {/* Citizen Submit */}
            <div className="lg:col-span-4 space-y-6">
              <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2 text-indigo-600">
                  <i className="fas fa-plus-circle"></i>
                  File New Report
                </h3>
                <form onSubmit={submitReport} className="space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                    <select name="category" required className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500">
                      {Object.values(ReportCategory).map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                    <textarea 
                      name="description" required rows={3}
                      placeholder="Briefly explain the issue..."
                      className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500"
                    ></textarea>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Location</label>
                    <input name="location" required placeholder="Where is it?" className="w-full p-3 rounded-xl border border-slate-200 bg-slate-50 outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Evidence</label>
                    <input name="media" type="file" accept="image/*,video/*" required className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:bg-indigo-50 file:text-indigo-700" />
                  </div>
                  <button 
                    disabled={isUploading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {isUploading ? <i className="fas fa-spinner animate-spin"></i> : <><i className="fas fa-paper-plane"></i> Submit</>}
                  </button>
                </form>
              </section>
            </div>

            {/* Citizen Feed */}
            <div className="lg:col-span-8 space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="font-bold text-xl text-slate-900">Community Reports</h3>
                {isLoading && <i className="fas fa-spinner animate-spin text-slate-400"></i>}
              </div>
              {reports.length === 0 && !isLoading && <p className="text-slate-500 italic">No reports found.</p>}
              {reports.map(report => (
                <div key={report.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm flex flex-col md:flex-row hover:border-indigo-200 transition-all">
                  <div className="md:w-48 h-48 bg-slate-100 flex-shrink-0">
                    {report.media_type === 'video' ? (
                      <video src={report.media_url} controls className="w-full h-full object-cover" />
                    ) : (
                      <img src={report.media_url} alt="Evidence" className="w-full h-full object-cover" />
                    )}
                  </div>
                  <div className="p-5 flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <span className={`px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider ${
                        report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {report.status}
                      </span>
                      <span className="text-[10px] text-slate-400 font-medium">
                        {new Date(report.timestamp).toLocaleDateString()}
                      </span>
                    </div>
                    <h4 className="font-bold text-lg text-slate-900 mb-1">{report.title}</h4>
                    <p className="text-slate-500 text-sm mb-3 font-medium flex items-center gap-1.5">
                      <i className="fas fa-map-marker-alt text-indigo-400"></i> {report.location}
                    </p>
                    <p className="text-slate-600 text-sm mb-4 line-clamp-2">"{report.description}"</p>

                    {report.status === ReportStatus.RESOLVED && (
                      <div className="mt-4 pt-4 border-t border-slate-100 flex items-center gap-4 text-green-600">
                        <i className="fas fa-check-circle text-xl"></i>
                        <div className="text-xs font-semibold">
                          Resolved: {report.work_done_description}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          /* Authority Dashboard */
          <div className="lg:col-span-12 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-slate-400 uppercase mb-2">Total Tickets</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.total}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-amber-500 uppercase mb-2">Pending</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.pending}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-green-500 uppercase mb-2">Resolved</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.resolved}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hidden lg:block">
                <p className="text-xs font-bold text-indigo-500 uppercase mb-2">Active Categories</p>
                <span className="text-3xl font-extrabold text-slate-900">{Object.keys(stats.byCategory).length}</span>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-md overflow-hidden">
              <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <h3 className="font-bold text-slate-900 text-lg">Report Queue</h3>
                <div className="text-xs text-slate-500 font-medium">Real-time monitoring active</div>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-100">
                      <th className="px-6 py-4">Report & Citizen</th>
                      <th className="px-6 py-4">Category</th>
                      <th className="px-6 py-4">Location</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4">Submitted</th>
                      <th className="px-6 py-4 text-center">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {reports.map(report => (
                      <tr key={report.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="relative">
                              <img src={report.media_url} className="w-12 h-12 rounded-xl object-cover shadow-sm" />
                              {report.media_type === 'video' && <i className="fas fa-play absolute inset-0 m-auto text-white text-[10px] bg-slate-900/40 w-fit h-fit p-1 rounded-full"></i>}
                            </div>
                            <div>
                              <p className="text-sm font-bold text-slate-900 line-clamp-1">{report.title}</p>
                              <p className="text-[10px] text-slate-400 font-semibold">{report.citizen_name}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="text-xs font-medium text-slate-600 bg-slate-100 px-2 py-1 rounded-lg">
                            {report.category}
                          </span>
                        </td>
                        <td className="px-6 py-4 max-w-[200px]">
                          <p className="text-xs text-slate-600 truncate flex items-center gap-1.5">
                            <i className="fas fa-map-marker-alt text-red-400"></i>
                            {report.location}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${
                            report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'
                          }`}>
                            {report.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-[10px] text-slate-500 font-medium">
                            {new Date(report.timestamp).toLocaleDateString()}<br/>
                            {new Date(report.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center justify-center gap-4">
                            <button 
                              onClick={() => setViewingReportId(report.id)}
                              className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center gap-1"
                            >
                              <i className="fas fa-eye"></i> View
                            </button>
                            {report.status !== ReportStatus.RESOLVED ? (
                              <button 
                                onClick={() => setResolvingId(report.id)}
                                className="text-xs font-bold text-emerald-600 hover:text-emerald-800 flex items-center gap-1"
