      )}

      {/* Resolution Modal */}
      {resolvingId && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden border border-white/20">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <div>
                <h3 className="font-bold text-slate-900">Upload Resolution Proof</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Case Reference: #{resolvingId.slice(0, 6)}</p>
              </div>
              <button onClick={() => setResolvingId(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleResolve} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase mb-1 tracking-widest">Work Description</label>
                <textarea 
                  name="resolution" required rows={4} 
                  className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium" 
                  placeholder="Summarize the corrective actions taken..."
                ></textarea>
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase mb-1 tracking-widest">Evidence of Work (Photo)</label>
                <div className="relative group">
                  <input 
                    name="work_media" type="file" accept="image/*" required 
                    className="w-full text-xs text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-xl file:border-0 file:bg-emerald-50 file:text-emerald-700 file:font-black" 
                  />
                </div>
              </div>
              <button 
                disabled={isUploading} 
                className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all disabled:opacity-50 active:scale-[0.98]"
              >
                {isUploading ? (
                  <span className="flex items-center justify-center gap-2"><i className="fas fa-spinner animate-spin"></i> Finalizing Case...</span>
                ) : (
                  <span className="flex items-center justify-center gap-2"><i className="fas fa-check-circle"></i> Mark as Resolved</span>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeReportMedia = async (base64Data: string, mimeType: string, description: string) => {
  try {
    const ai = getAI();
    const model = 'gemini-3-flash-preview';

    const imagePart = {
      inlineData: {
        mimeType,
        data: base64Data.split(',')[1] || base64Data,
      },
    };

    const prompt = `
      Analyze this image of a citizen report regarding "${description}". 
      1. Briefly describe what is seen.
      2. Categorize the severity (Low, Medium, High).
      3. Suggest 3 immediate action steps for local authorities.
      Format the response as a clean summary.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: { parts: [imagePart, { text: prompt }] },
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis failed:", error);
    return "AI analysis unavailable at this time.";
  }
};

export const getResolutionSummary = async (originalDesc: string, resolutionDesc: string) => {
  try {
    const ai = getAI();
    const model = 'gemini-3-flash-preview';

    const prompt = `
      Issue Reported: ${originalDesc}
      Resolution provided by Authority: ${resolutionDesc}

      Generate a concise, professional notification message for the citizen informing them that the work is complete.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    return "The reported issue has been resolved. Thank you for your patience.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/ai';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  // Forgot Password State
  const [forgotPasswordStep, setForgotPasswordStep] = useState<'none' | 'identify' | 'otp' | 'reset'>('none');
  const [resetTargetUser, setResetTargetUser] = useState<any>(null);
  const [generatedOtp, setGeneratedOtp] = useState<string>('');
  const [enteredOtp, setEnteredOtp] = useState<string>('');

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleAuth = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });

      const newUser: User = {
        id: `auth_${username}`,
        username,
        email: 'authority@civicsense.gov',
        mobile: '',
        role: 'authority'
      };
      setUser(newUser);
      setView('dashboard');
      return;
    }

    // Citizen Logic
    if (isSignUp) {
      if (password !== confirmPassword) {
        alert("Passwords do not match!");
        return;
      }

      // Check if user exists
      const { data: existingUser } = await supabase
        .from('users')
        .select('*')
        .or(`username.eq.${username},email.eq.${email}`)
        .single();

      if (existingUser) {
        alert("Username or Email already exists. Please sign in.");
        setIsSignUp(false);
        return;
      }

      const userId = `cit_${Math.random().toString(36).substr(2, 9)}`;
      const { error: signUpError } = await supabase.from('users').insert({
        id: userId,
        username,
        password, 
        email,
        mobile,
        role: 'citizen'
      });

      if (signUpError) {
        alert("Error signing up: " + signUpError.message);
        return;
      }

      alert("Account created successfully! Please sign in.");
      setIsSignUp(false);
    } else {
      // Sign In Logic
      const { data: userData, error: signInError } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (signInError || !userData) {
        alert("Invalid username or password.");
        return;
      }

      setUser(userData as User);
      setView('dashboard');
    }
  };

  const initiateForgotPassword = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const identifier = new FormData(e.currentTarget).get('identifier') as string;

    // Find user by username or email
    const { data: userData, error } = await supabase
      .from('users')
      .select('*')
      .or(`username.eq.${identifier},email.eq.${identifier}`)
      .single();

    if (error || !userData) {
      alert("No user found with that detail.");
      return;
    }

    // Simulate sending OTP
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(otp);
    setResetTargetUser(userData);
    setForgotPasswordStep('otp');

    // Show user the "sent" location
    const mask = (str: string) => str.slice(0, 3) + '***' + str.slice(-2);
    alert(`A 6-digit OTP has been sent to ${mask(userData.email)} and ${mask(userData.mobile)}.\n(Demo OTP: ${otp})`);
  };

  const verifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (enteredOtp === generatedOtp) {
      setForgotPasswordStep('reset');
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  const finalizeReset = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newPass = formData.get('newPassword') as string;
    const confirmPass = formData.get('confirmNewPassword') as string;

    if (newPass !== confirmPass) {
      alert("Passwords do not match.");
      return;
    }

    const { error } = await supabase
      .from('users')
      .update({ password: newPass })
      .eq('id', resetTargetUser.id);

    if (error) {
      alert("Failed to update password.");
    } else {
      alert("Password updated successfully. You can now login.");
      setForgotPasswordStep('none');
      setResetTargetUser(null);
    }
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    setView('login');
    setRole('citizen');
    setIsSignUp(false);
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to submit report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  const viewingReport = useMemo(() => 
    reports.find(r => r.id === viewingReportId), 
    [viewingReportId, reports]
  );

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-900 overflow-hidden relative">
        <div className="absolute top-0 -left-10 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-0 -right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>

        <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md border border-slate-100 z-10">
          {forgotPasswordStep === 'none' ? (
            <>
              <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl text-white mb-4 shadow-lg transform rotate-3 transition-transform hover:rotate-0">
                  <i className="fas fa-landmark text-2xl"></i>
                </div>
                <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CivicSense</h1>
                <p className="text-slate-500 text-sm mt-1">Smart Governance Portal</p>
              </div>

              <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
                <button 
                  onClick={() => { setRole('citizen'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'citizen' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Citizen
                </button>
                <button 
                  onClick={() => { setRole('authority'); setIsSignUp(false); }}
                  className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${role === 'authority' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Authority
                </button>
              </div>

              <form onSubmit={handleAuth} className="space-y-4">
                <h2 className="text-xl font-bold text-slate-800 mb-2">
                  {role === 'authority' ? 'Authority Access' : (isSignUp ? 'Join Community' : 'Welcome Back')}
                </h2>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Username</label>
                  <input 
                    name="username" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="Enter username" 
                  />
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Password</label>
                  <input 
                    name="password" type="password" required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                    placeholder="••••••••" 
                  />
                </div>

                {role === 'citizen' && isSignUp && (
                  <>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Confirm Password</label>
                      <input 
                        name="confirmPassword" type="password" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="••••••••" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Email <span className="text-red-500">*</span></label>
                      <input 
                        name="email" type="email" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="email@example.com" 
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Mobile No. <span className="text-red-500">*</span></label>
                      <input 
                        name="mobile" type="tel" required
                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 transition-all outline-none" 
                        placeholder="+91 00000 00000" 
                      />
                    </div>
                  </>
                )}

                {!isSignUp && role === 'citizen' && (
                  <div className="flex justify-end">
                    <button 
                      type="button" 
                      onClick={() => setForgotPasswordStep('identify')}
                      className="text-xs font-semibold text-indigo-500 hover:text-indigo-700"
                    >
                      Forgot Password?
                    </button>
                  </div>
                )}

                <button 
                  type="submit"
                  className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] mt-4"
                >
                  {role === 'authority' || !isSignUp ? 'Login' : 'Create Account'} <i className="fas fa-arrow-right ml-2 text-sm opacity-50"></i>
                </button>

                {role === 'citizen' && (
                  <div className="text-center mt-4">
                    <button 
                      type="button"
                      onClick={() => setIsSignUp(!isSignUp)}
                      className="text-sm font-semibold text-indigo-600 hover:text-indigo-800 transition-colors"
                    >
                      {isSignUp ? 'Already have an account? Sign In' : "Don't have an account? Sign Up"}
                    </button>
                  </div>
                )}
              </form>
            </>
          ) : (
            <div className="space-y-6">
              <div className="text-center">
                <div className="w-12 h-12 bg-amber-100 text-amber-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-key text-xl"></i>
                </div>
                <h2 className="text-2xl font-bold text-slate-800">Reset Password</h2>
                <p className="text-slate-500 text-sm mt-1">
