              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-amber-500 uppercase mb-2">Pending</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.pending}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <p className="text-xs font-bold text-green-500 uppercase mb-2">Resolved</p>
                <span className="text-3xl font-extrabold text-slate-900">{stats.resolved}</span>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hidden lg:block">
                <p className="text-xs font-bold text-indigo-500 uppercase mb-2">Active Categories</p>
                <span className="text-3xl font-extrabold text-slate-900">{Object.keys(stats.byCategory).length}</span>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-md overflow-hidden">
              <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <h3 className="font-bold text-slate-900 text-lg">Report Queue</h3>
                <div className="text-xs text-slate-500 font-medium">Real-time monitoring active</div>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-100">
                      <th className="px-6 py-4">Report & Citizen</th>
                      <th className="px-6 py-4">Category</th>
                      <th className="px-6 py-4">Location</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4">Submitted</th>
                      <th className="px-6 py-4 text-center">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {reports.map(report => (
                      <tr key={report.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="relative">
                              <img src={report.media_url} className="w-12 h-12 rounded-xl object-cover shadow-sm" />
                              {report.media_type === 'video' && <i className="fas fa-play absolute inset-0 m-auto text-white text-[10px] bg-slate-900/40 w-fit h-fit p-1 rounded-full"></i>}
                            </div>
                            <div>
                              <p className="text-sm font-bold text-slate-900 line-clamp-1">{report.title}</p>
                              <p className="text-[10px] text-slate-400 font-semibold">{report.citizen_name}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className="text-xs font-medium text-slate-600 bg-slate-100 px-2 py-1 rounded-lg">
                            {report.category}
                          </span>
                        </td>
                        <td className="px-6 py-4 max-w-[200px]">
                          <p className="text-xs text-slate-600 truncate flex items-center gap-1.5">
                            <i className="fas fa-map-marker-alt text-red-400"></i>
                            {report.location}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${
                            report.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'
                          }`}>
                            {report.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-[10px] text-slate-500 font-medium">
                            {new Date(report.timestamp).toLocaleDateString()}<br/>
                            {new Date(report.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center justify-center gap-4">
                            <button 
                              onClick={() => setViewingReportId(report.id)}
                              className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center gap-1"
                            >
                              <i className="fas fa-eye"></i> View
                            </button>
                            {report.status !== ReportStatus.RESOLVED ? (
                              <button 
                                onClick={() => setResolvingId(report.id)}
                                className="text-xs font-bold text-emerald-600 hover:text-emerald-800 flex items-center gap-1"
                              >
                                <i className="fas fa-check"></i> Resolve
                              </button>
                            ) : (
                              <span className="text-[10px] text-slate-400 font-bold uppercase italic">Completed</span>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              {reports.length === 0 && (
                <div className="p-12 text-center">
                  <i className="fas fa-inbox text-4xl text-slate-200 mb-4"></i>
                  <p className="text-slate-400 italic">No reports waiting in the queue.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Report Details Modal */}
      {viewingReportId && viewingReport && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md transition-all">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col">
            <div className="p-6 border-b border-slate-100 bg-white flex items-center justify-between sticky top-0 z-10">
              <div>
                <h3 className="text-2xl font-black text-slate-900 tracking-tight">Report Details</h3>
                <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mt-1">ID: {viewingReport.id.slice(0, 8)}</p>
              </div>
              <button 
                onClick={() => setViewingReportId(null)}
                className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-slate-100 text-slate-400 transition-all"
              >
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>

            <div className="overflow-y-auto p-6 md:p-8">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Media Section */}
                <div className="space-y-4">
                  <div className="rounded-2xl overflow-hidden border border-slate-200 shadow-sm bg-slate-50">
                    {viewingReport.media_type === 'video' ? (
                      <video src={viewingReport.media_url} controls className="w-full h-auto aspect-video object-cover" />
                    ) : (
                      <img src={viewingReport.media_url} alt="Report Evidence" className="w-full h-auto object-cover" />
                    )}
                  </div>
                  <div className="flex gap-4 items-center p-4 bg-indigo-50 rounded-2xl">
                    <div className="w-10 h-10 bg-indigo-600 text-white rounded-xl flex items-center justify-center">
                      <i className="fas fa-info-circle"></i>
                    </div>
                    <div>
                      <p className="text-xs font-bold text-indigo-900 uppercase">Submission Context</p>
                      <p className="text-xs text-indigo-700 font-medium">Reported by {viewingReport.citizen_name} on {new Date(viewingReport.timestamp).toLocaleString()}</p>
                    </div>
                  </div>
                </div>

                {/* Content Section */}
                <div className="space-y-6">
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <span className="bg-indigo-100 text-indigo-700 text-[10px] font-black px-2 py-0.5 rounded uppercase">{viewingReport.category}</span>
                      <span className={`text-[10px] font-black px-2 py-0.5 rounded uppercase ${
                        viewingReport.status === ReportStatus.RESOLVED ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {viewingReport.status}
                      </span>
                    </div>
                    <h4 className="text-3xl font-extrabold text-slate-900 leading-tight">{viewingReport.title}</h4>
                    <p className="text-lg text-slate-500 font-medium flex items-center gap-2">
                      <i className="fas fa-map-marker-alt text-red-500"></i> {viewingReport.location}
                    </p>
                  </div>

                  <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100">
                    <h5 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                      <i className="fas fa-comment-alt"></i> Citizen Description
                    </h5>
                    <p className="text-slate-700 leading-relaxed font-medium">
                      "{viewingReport.description}"
                    </p>
                  </div>

                  {viewingReport.ai_analysis && (
                    <div className="p-6 bg-indigo-900 rounded-3xl text-white shadow-xl shadow-indigo-200">
                      <h5 className="text-xs font-black text-indigo-300 uppercase tracking-widest mb-4 flex items-center gap-2">
                        <i className="fas fa-robot"></i> Advanced AI Analysis & Recommendations
                      </h5>
                      <div className="text-sm leading-relaxed prose prose-invert max-w-none prose-sm whitespace-pre-wrap font-medium opacity-90">
                        {viewingReport.ai_analysis}
                      </div>
                    </div>
                  )}

                  {viewingReport.status === ReportStatus.RESOLVED && (
                    <div className="p-6 bg-emerald-50 rounded-3xl border border-emerald-100 border-2">
                      <h5 className="text-xs font-black text-emerald-600 uppercase tracking-widest mb-3 flex items-center gap-2">
                        <i className="fas fa-check-double"></i> Resolution Details
                      </h5>
                      <div className="flex gap-4">
                        {viewingReport.work_done_media_url && (
                          <img src={viewingReport.work_done_media_url} className="w-24 h-24 rounded-xl object-cover border border-emerald-200" />
                        )}
                        <div>
                          <p className="text-emerald-900 font-bold mb-1">Status: Resolved</p>
                          <p className="text-emerald-700 text-sm leading-relaxed font-medium">"{viewingReport.work_done_description}"</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex items-center justify-between">
              <button 
                onClick={() => setViewingReportId(null)}
                className="text-sm font-bold text-slate-500 hover:text-slate-800"
              >
                Back to Dashboard
              </button>
              {viewingReport.status !== ReportStatus.RESOLVED && (
                <button 
                  onClick={() => { setViewingReportId(null); setResolvingId(viewingReport.id); }}
                  className="bg-indigo-600 text-white font-bold py-3 px-8 rounded-2xl shadow-lg hover:bg-indigo-700 transition-all flex items-center gap-2"
                >
                  <i className="fas fa-tools"></i> Resolve Issue
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Resolution Modal */}
      {resolvingId && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden border border-white/20">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <div>
                <h3 className="font-bold text-slate-900">Upload Resolution Proof</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Case Reference: #{resolvingId.slice(0, 6)}</p>
              </div>
              <button onClick={() => setResolvingId(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleResolve} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase mb-1 tracking-widest">Work Description</label>
                <textarea 
                  name="resolution" required rows={4} 
                  className="w-full p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium" 
                  placeholder="Summarize the corrective actions taken..."
                ></textarea>
              </div>
              <div>
                <label className="block text-xs font-black text-slate-500 uppercase mb-1 tracking-widest">Evidence of Work (Photo)</label>
                <div className="relative group">
                  <input 
                    name="work_media" type="file" accept="image/*" required 
                    className="w-full text-xs text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-xl file:border-0 file:bg-emerald-50 file:text-emerald-700 file:font-black" 
                  />
                </div>
              </div>
              <button 
                disabled={isUploading} 
                className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all disabled:opacity-50 active:scale-[0.98]"
              >
                {isUploading ? (
                  <span className="flex items-center justify-center gap-2"><i className="fas fa-spinner animate-spin"></i> Finalizing Case...</span>
                ) : (
                  <span className="flex items-center justify-center gap-2"><i className="fas fa-check-circle"></i> Mark as Resolved</span>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, Report, ReportStatus, ReportCategory 
} from './types';
import { analyzeReportMedia, getResolutionSummary } from './services/ai';
import { supabase } from './lib/supabase';

// Internal Hardcoded Authority Credentials
const AUTH_CREDENTIALS = {
  username: 'Atharv',
  password: 'Civicsense'
};

const STORAGE_KEY = 'civicsense_user_session';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>([]);
  const [view, setView] = useState<'login' | 'dashboard'>('login');
  const [role, setRole] = useState<'citizen' | 'authority'>('citizen');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [resolvingId, setResolvingId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  // Forgot Password State
  const [forgotPasswordStep, setForgotPasswordStep] = useState<'none' | 'identify' | 'otp' | 'reset'>('none');
  const [resetTargetUser, setResetTargetUser] = useState<any>(null);
  const [generatedOtp, setGeneratedOtp] = useState<string>('');
  const [enteredOtp, setEnteredOtp] = useState<string>('');

  // Session Persistence Effect
  useEffect(() => {
    const savedUser = localStorage.getItem(STORAGE_KEY);
    if (savedUser) {
      try {
        const parsedUser = JSON.parse(savedUser) as User;
        setUser(parsedUser);
        setView('dashboard');
        setRole(parsedUser.role);
      } catch (e) {
        console.error("Failed to parse saved session", e);
        localStorage.removeItem(STORAGE_KEY);
      }
    }
  }, []);

  // Analytics for Authority
  const stats = useMemo(() => {
    return {
      total: reports.length,
      pending: reports.filter(r => r.status !== ReportStatus.RESOLVED).length,
      resolved: reports.filter(r => r.status === ReportStatus.RESOLVED).length,
      byCategory: reports.reduce((acc, r) => {
        acc[r.category] = (acc[r.category] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    };
  }, [reports]);

  // Initial Fetch & Subscription
  useEffect(() => {
    const fetchReports = async () => {
      try {
        const { data, error } = await supabase
          .from('reports')
          .select('*')
          .order('timestamp', { ascending: false });

        if (!error && data) {
          setReports(data as Report[]);
        }
      } catch (err) {
        console.error("Supabase fetch error:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchReports();

    const channels = supabase.channel('realtime-reports')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'reports' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            setReports(prev => [payload.new as Report, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            setReports(prev => prev.map(r => r.id === payload.new.id ? payload.new as Report : r));
          } else if (payload.eventType === 'DELETE') {
            setReports(prev => prev.filter(r => r.id !== payload.old.id));
          }
        }
      )
      .subscribe();

    return () => {
      channels.unsubscribe();
    };
  }, []);

  const handleAuth = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const username = formData.get('username') as string;
    const password = formData.get('password') as string;
    const confirmPassword = formData.get('confirmPassword') as string;
    const email = formData.get('email') as string || '';
    const mobile = formData.get('mobile') as string || '';

    if (role === 'authority') {
      if (username !== AUTH_CREDENTIALS.username || password !== AUTH_CREDENTIALS.password) {
        alert("Invalid Authority Credentials.");
        return;
      }

      // Check for max 5 members
      const { data: sessions, error: sessionError } = await supabase
        .from('auth_sessions')
        .select('*');

      if (sessionError) {
        alert("Database connection error: " + sessionError.message);
        return;
      }

      const existingSession = sessions.find(s => s.username === username);
      if (sessions.length >= 5 && !existingSession) {
        alert("Maximum 5 concurrent authority sessions are active.");
        return;
      }

      await supabase.from('auth_sessions').upsert({ 
        username, 
        last_active: new Date().toISOString() 
      });

      const newUser: User = {
        id: `auth_${username}`,
        username,
        email: 'authority@civicsense.gov',
        mobile: '',
        role: 'authority'
      };
      setUser(newUser);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newUser));
      setView('dashboard');
      return;
    }

    // Citizen Logic
    if (isSignUp) {
      if (password !== confirmPassword) {
        alert("Passwords do not match!");
        return;
      }

      const { data: existingUser } = await supabase
        .from('users')
        .select('*')
        .or(`username.eq.${username},email.eq.${email}`)
        .single();

      if (existingUser) {
        alert("Username or Email already exists. Please sign in.");
        setIsSignUp(false);
        return;
      }

      const userId = `cit_${Math.random().toString(36).substr(2, 9)}`;
      const { error: signUpError } = await supabase.from('users').insert({
        id: userId,
        username,
        password, 
        email,
        mobile,
        role: 'citizen'
      });

      if (signUpError) {
        alert("Error signing up: " + signUpError.message);
        return;
      }

      alert("Welcome to the community! Your account is ready. Please sign in.");
      setIsSignUp(false);
    } else {
      const { data: userData, error: signInError } = await supabase
        .from('users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (signInError || !userData) {
        alert("Invalid username or password.");
        return;
      }

      const loggedUser = userData as User;
      setUser(loggedUser);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(loggedUser));
      setView('dashboard');
    }
  };

  const initiateForgotPassword = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const identifier = new FormData(e.currentTarget).get('identifier') as string;

    const { data: userData, error } = await supabase
      .from('users')
      .select('*')
      .or(`username.eq.${identifier},email.eq.${identifier}`)
      .single();

    if (error || !userData) {
      alert("We couldn't find an account with that information.");
      return;
    }

    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(otp);
    setResetTargetUser(userData);
    setForgotPasswordStep('otp');

    const mask = (str: string) => str.slice(0, 3) + '***' + str.slice(-2);
    alert(`A 6-digit verification code has been sent to ${mask(userData.email)}.\n(Demo Code: ${otp})`);
  };

  const verifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (enteredOtp === generatedOtp) {
      setForgotPasswordStep('reset');
    } else {
      alert("The code you entered is incorrect. Try again.");
    }
  };

  const finalizeReset = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newPass = formData.get('newPassword') as string;
    const confirmPass = formData.get('confirmNewPassword') as string;

    if (newPass !== confirmPass) {
      alert("Oops! The passwords don't match.");
      return;
    }

    const { error } = await supabase
      .from('users')
      .update({ password: newPass })
      .eq('id', resetTargetUser.id);

    if (error) {
      alert("Something went wrong while updating your password.");
    } else {
      alert("Success! Your password is now updated. Log in to continue.");
      setForgotPasswordStep('none');
      setResetTargetUser(null);
    }
  };

  const handleLogout = async () => {
    if (user?.role === 'authority') {
      await supabase
        .from('auth_sessions')
        .delete()
        .eq('username', user.username);
    }
    setUser(null);
    localStorage.removeItem(STORAGE_KEY);
    setView('login');
    setRole('citizen');
    setIsSignUp(false);
  };

  const submitReport = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const file = formData.get('media') as File;
    const category = formData.get('category') as ReportCategory;
    const description = formData.get('description') as string;
    const location = formData.get('location') as string;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      const aiAnalysis = await analyzeReportMedia(base64, file.type, description);

      const newReportData = {
        citizen_id: user.id,
        citizen_name: user.username,
        title: `${category} Report`,
        description,
        category,
        location,
        timestamp: Date.now(),
        status: ReportStatus.PENDING,
        media_url: base64,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        ai_analysis: aiAnalysis,
        notified: false
      };

      const { error } = await supabase
        .from('reports')
        .insert([newReportData]);

      if (error) {
        alert("Failed to share report: " + error.message);
      } else {
        (e.target as HTMLFormElement).reset();
        alert("Wonderful! Your report has been shared with the community.");
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResolve = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!resolvingId) return;
    setIsUploading(true);

    const formData = new FormData(e.currentTarget);
    const resolutionDesc = formData.get('resolution') as string;
    const mediaFile = formData.get('work_media') as File;

    const report = reports.find(r => r.id === resolvingId);
    if (!report) return;

    let workDoneMediaUrl = '';
    if (mediaFile && mediaFile.size > 0) {
      const reader = new FileReader();
      const promise = new Promise<string>((resolve) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(mediaFile);
      });
      workDoneMediaUrl = await promise;
    }

    const aiSummary = await getResolutionSummary(report.description, resolutionDesc);

    const { error } = await supabase
      .from('reports')
      .update({
        status: ReportStatus.RESOLVED,
        work_done_description: resolutionDesc,
        work_done_media_url: workDoneMediaUrl,
        resolved_at: Date.now(),
        ai_analysis: aiSummary
      })
      .eq('id', resolvingId);

    if (error) {
      alert("Error resolving case: " + error.message);
    } else {
      setResolvingId(null);
    }
    setIsUploading(false);
  };

  const viewingReport = useMemo(() => 
    reports.find(r => r.id === viewingReportId), 
    [viewingReportId, reports]
  );

  if (view === 'login') {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-gradient-to-br from-indigo-900 via-slate-900 to-purple-900 overflow-hidden relative">
