                  <form onSubmit={submitReport} className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Type of Issue</label>
                      <select name="category" required className="w-full p-4 rounded-2xl border border-slate-100 bg-slate-50 outline-none focus:ring-4 focus:ring-indigo-500/10 font-bold text-slate-700">
