                    <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                      <th className="px-6 py-4">Evidence</th>
                      <th className="px-6 py-4">Report Details</th>
                      <th className="px-6 py-4">Location</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4 text-center">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {reports.map(report => (
                      <tr key={report.id} className="bg-white hover:bg-slate-50 transition-all rounded-[2rem] group">
                        <td className="px-6 py-4 first:rounded-l-[2rem]">
                          <div className="relative w-16 h-16 rounded-2xl overflow-hidden shadow-md">
                            <img src={report.media_url} className="w-full h-full object-cover" />
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm font-black text-slate-900 mb-0.5">{report.title}</p>
                          <p className="text-[10px] font-bold text-indigo-500 uppercase">{report.citizen_name}</p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2 text-xs font-bold text-slate-500">
                            <i className="fas fa-map-pin text-rose-500"></i>
                            {report.location}
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`text-[9px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest ${
                            report.status === ReportStatus.RESOLVED ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100'
                          }`}>
                            {report.status}
                          </span>
                        </td>
                        <td className="px-6 py-4 last:rounded-r-[2rem] text-center">
                          <div className="flex items-center justify-center gap-4">
                            <button onClick={() => setViewingReportId(report.id)} className="w-10 h-10 rounded-xl bg-slate-100 text-slate-600 hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center shadow-sm">
                              <i className="fas fa-expand-alt text-sm"></i>
                            </button>
                            {report.status !== ReportStatus.RESOLVED && (
                              <button onClick={() => setResolvingId(report.id)} className="w-10 h-10 rounded-xl bg-emerald-50 text-emerald-600 hover:bg-emerald-600 hover:text-white transition-all flex items-center justify-center shadow-sm border border-emerald-100">
                                <i className="fas fa-check text-sm"></i>
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </main>

      {viewingReportId && viewingReport && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl">
          <div className="bg-white rounded-[3rem] w-full max-w-5xl max-h-[92vh] overflow-hidden flex flex-col transform">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-3xl font-black text-slate-900 tracking-tight">Report Details</h3>
              <button onClick={() => setViewingReportId(null)} className="w-12 h-12 flex items-center justify-center rounded-2xl hover:bg-slate-100 text-slate-400">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>
            <div className="overflow-y-auto p-8 md:p-12">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                <div className="space-y-6">
                  <div className="rounded-[2.5rem] overflow-hidden border border-slate-100 shadow-2xl bg-slate-100">
                    {viewingReport.media_type === 'video' ? (
                      <video src={viewingReport.media_url} controls className="w-full h-auto aspect-square object-cover" />
                    ) : (
                      <img src={viewingReport.media_url} alt="Evidence" className="w-full h-auto object-cover" />
                    )}
                  </div>
                </div>
                <div className="space-y-8">
                  <div className="space-y-4">
                    <span className="bg-indigo-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest">{viewingReport.category}</span>
                    <h4 className="text-5xl font-black text-slate-900 leading-[0.9] tracking-tighter">{viewingReport.title}</h4>
                    <p className="text-2xl text-slate-400 font-black flex items-center gap-3">
                      <i className="fas fa-location-arrow text-rose-500"></i> {viewingReport.location}
                    </p>
                  </div>
                  <div className="p-8 bg-slate-900 rounded-[2.5rem] text-white">
                    <h5 className="text-[10px] font-black text-slate-400 uppercase mb-4">Statement</h5>
                    <p className="text-xl leading-relaxed font-bold italic opacity-90">"{viewingReport.description}"</p>
                    {user?.role === 'authority' && <p className="mt-4 text-xs font-black text-indigo-400">— Reported by {viewingReport.citizen_name}</p>}
                  </div>
                  {viewingReport.ai_analysis && (
                    <div className="p-8 bg-indigo-50/50 rounded-[2.5rem] border-2 border-dashed border-indigo-200">
                      <h5 className="text-[10px] font-black text-indigo-500 uppercase mb-4 flex items-center gap-2">
                        <i className="fas fa-brain"></i> AI Assessment
                      </h5>
                      <div className="text-sm font-bold text-slate-700 leading-relaxed whitespace-pre-wrap">{viewingReport.ai_analysis}</div>
                    </div>
                  )}
                  {viewingReport.status === ReportStatus.RESOLVED && (
                    <div className="p-8 bg-emerald-600 rounded-[2.5rem] text-white">
                      <h5 className="text-[10px] font-black text-emerald-200 uppercase mb-4">Resolution Proof</h5>
                      <div className="flex gap-6">
                        {viewingReport.work_done_media_url && (
                          <img src={viewingReport.work_done_media_url} className="w-28 h-28 rounded-3xl object-cover border-4 border-white/20" />
                        )}
                        <div>
                          <p className="font-black text-xl mb-2">Resolved Successfully</p>
                          <p className="text-emerald-50 text-sm font-bold opacity-90">"{viewingReport.work_done_description}"</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
            <div className="p-8 border-t border-slate-100 bg-white">
              <button onClick={() => setViewingReportId(null)} className="px-8 py-4 text-sm font-black text-slate-400 hover:text-slate-900">Close</button>
            </div>
          </div>
        </div>
      )}

      {resolvingId && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg overflow-hidden border border-white/20">
            <div className="p-8 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Resolve Case</h3>
              <button onClick={() => setResolvingId(null)} className="w-10 h-10 rounded-xl bg-white border border-slate-200 text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleResolve} className="p-8 space-y-8">
              <textarea name="resolution" required rows={4} className="w-full p-5 rounded-[2rem] bg-slate-50 border border-slate-100 outline-none font-bold text-slate-700 resize-none" placeholder="Describe the resolution steps taken..."></textarea>
              <label className="flex items-center gap-3 p-4 border-2 border-dashed border-emerald-200 rounded-[1.5rem] cursor-pointer bg-emerald-50/20">
                <i className="fas fa-camera text-emerald-400 text-xl"></i>
                <p className="text-xs font-black text-emerald-700">Attach Evidence of Work</p>
                <input name="work_media" type="file" accept="image/*" required className="hidden" />
              </label>
              <button disabled={isUploading} className="w-full py-5 bg-emerald-600 text-white rounded-[2rem] font-black shadow-xl">
                {isUploading ? "Processing..." : "Mark as Resolved"}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
